1	import {
2	  dehydrate,
3	  hydrate,
4	  type DehydratedState,
5	  type Query,
6	  type QueryClient,
7	  type QueryKey,
8	} from '@tanstack/react-query';
9	
10	const DB_NAME = 'fitcommerce-offline-cache';
11	const STORE_NAME = 'app-state';
12	const QUERY_CACHE_KEY = 'react-query';
13	const QUERY_CACHE_VERSION = 1;
14	const MUTATION_QUEUE_KEY = 'offline-mutations';
15	const MUTATION_QUEUE_VERSION = 1;
16	
17	const OFFLINE_QUERY_ROOTS = new Set([
18	  'dashboard',
19	  'items',
20	  'campaigns',
21	  'orders',
22	  'inventory',
23	  'purchase-orders',
24	  'suppliers',
25	  'variances',
26	  'reports',
27	  'exports',
28	  'warehouse-bins',
29	  'locations',
30	  'members',
31	  'coaches',
32	  'landed-costs',
33	  // Admin read domains — persisted so admins can review data while offline
34	  'users',
35	  'audit',
36	  'backups',
37	  'biometrics',
38	  'encryption-keys',
39	  'retention-policies',
40	]);
41	
42	interface PersistedQuerySnapshot {
43	  version: number;
44	  updatedAt: number;
45	  state: DehydratedState;
46	}
47	
48	export type OfflineMutationType = 'create-item' | 'update-item' | 'run-export';
49	
50	export interface OfflineMutationEntry {
51	  id: string;
52	  type: OfflineMutationType;
53	  payload: Record<string, unknown>;
54	  createdAt: number;
55	}
56	
57	interface PersistedMutationQueue {
58	  version: number;
59	  updatedAt: number;
60	  mutations: OfflineMutationEntry[];
61	}
62	
63	function openDatabase(): Promise<IDBDatabase> {
64	  return new Promise((resolve, reject) => {
65	    const request = window.indexedDB.open(DB_NAME, 1);
66	    request.onerror = () => reject(request.error);
67	    request.onupgradeneeded = () => {
68	      const database = request.result;
69	      if (!database.objectStoreNames.contains(STORE_NAME)) {
70	        database.createObjectStore(STORE_NAME);
71	      }
72	    };
73	    request.onsuccess = () => resolve(request.result);
74	  });
75	}
76	
77	async function readStoreValue<T>(key: string): Promise<T | null> {
78	  const database = await openDatabase();
79	  return new Promise((resolve, reject) => {
80	    const transaction = database.transaction(STORE_NAME, 'readonly');
81	    const store = transaction.objectStore(STORE_NAME);
82	    const request = store.get(key);
83	    request.onerror = () => reject(request.error);
84	    request.onsuccess = () => resolve((request.result as T | undefined) ?? null);
85	    transaction.oncomplete = () => database.close();
86	    transaction.onerror = () => reject(transaction.error);
87	  });
88	}
89	
90	async function writeStoreValue<T>(key: string, value: T): Promise<void> {
91	  const database = await openDatabase();
92	  return new Promise((resolve, reject) => {
93	    const transaction = database.transaction(STORE_NAME, 'readwrite');
94	    const store = transaction.objectStore(STORE_NAME);
95	    const request = store.put(value, key);
96	    request.onerror = () => reject(request.error);
97	    transaction.oncomplete = () => {
98	      database.close();
99	      resolve();
100	    };
101	    transaction.onerror = () => reject(transaction.error);
102	  });
103	}
104	
105	function isOfflineCacheableQuery(query: Query): boolean {
106	  return query.state.status === 'success' && isOfflineCacheableQueryKey(query.queryKey);
107	}
108	
109	export function isOfflineCacheableQueryKey(queryKey: QueryKey): boolean {
110	  const root = Array.isArray(queryKey) ? queryKey[0] : undefined;
111	  return typeof root === 'string' && OFFLINE_QUERY_ROOTS.has(root);
112	}
113	
114	export async function loadPersistedQuerySnapshot(): Promise<PersistedQuerySnapshot | null> {
115	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
116	    return null;
117	  }
118	  const snapshot = await readStoreValue<PersistedQuerySnapshot>(QUERY_CACHE_KEY);
119	  if (!snapshot || snapshot.version !== QUERY_CACHE_VERSION) {
120	    return null;
121	  }
122	  return snapshot;
123	}
124	
125	export function hydrateOfflineQueryCache(queryClient: QueryClient, snapshot: PersistedQuerySnapshot | null): void {
126	  if (!snapshot) {
127	    return;
128	  }
129	  hydrate(queryClient, snapshot.state);
130	}
131	
132	export async function persistOfflineQueryCache(queryClient: QueryClient): Promise<number | null> {
133	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
134	    return null;
135	  }
136	
137	  const snapshot: PersistedQuerySnapshot = {
138	    version: QUERY_CACHE_VERSION,
139	    updatedAt: Date.now(),
140	    state: dehydrate(queryClient, {
141	      shouldDehydrateQuery: isOfflineCacheableQuery,
142	    }),
143	  };
144	
145	  await writeStoreValue(QUERY_CACHE_KEY, snapshot);
146	  return snapshot.updatedAt;
147	}
148	
149	export async function loadPendingOfflineMutations(): Promise<OfflineMutationEntry[]> {
150	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
151	    return [];
152	  }
153	
154	  const persisted = await readStoreValue<PersistedMutationQueue>(MUTATION_QUEUE_KEY);
155	  if (!persisted || persisted.version !== MUTATION_QUEUE_VERSION) {
156	    return [];
157	  }
158	  return persisted.mutations;
159	}
160	
161	export async function enqueueOfflineMutation(entry: OfflineMutationEntry): Promise<void> {
162	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
163	    return;
164	  }
165	
166	  const existing = await loadPendingOfflineMutations();
167	  const queue: PersistedMutationQueue = {
168	    version: MUTATION_QUEUE_VERSION,
169	    updatedAt: Date.now(),
170	    mutations: [...existing, entry],
171	  };
172	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
173	}
174	
175	export async function removeOfflineMutation(id: string): Promise<void> {
176	  if (typeof window === 'undefined' || !('indexedDB' in window)) {
177	    return;
178	  }
179	
180	  const existing = await loadPendingOfflineMutations();
181	  const queue: PersistedMutationQueue = {
182	    version: MUTATION_QUEUE_VERSION,
183	    updatedAt: Date.now(),
184	    mutations: existing.filter((entry) => entry.id !== id),
185	  };
186	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
187	}
