340	func sanitizeReportFilters(reportType string, filters map[string]string) map[string]string {
341		if len(filters) == 0 {
342			return nil
343		}
344		allowedByReportType := map[string]map[string]bool{
345			"member_growth":      {"location_id": true, "status": true, "from": true, "to": true},
346			"churn":              {"location_id": true, "from": true, "to": true},
347			"renewal_rate":       {"location_id": true},
348			"engagement":         {"status": true, "from": true, "to": true},
349			"class_fill_rate":    {"status": true, "from": true, "to": true},
350			"coach_productivity": {"location_id": true, "coach_id": true},
351			"inventory_summary":  {"category": true, "status": true},
352			"procurement_summary": {"status": true, "from": true, "to": true},
353			"landed_cost_report": {"item_id": true, "purchase_order_id": true, "period": true, "from": true, "to": true},
354		}
355	
356		allowed := allowedByReportType[reportType]
357		if len(allowed) == 0 {
358			return nil
359		}
360	
361		sanitized := make(map[string]string)
362		for key, value := range filters {
363			if allowed[key] && value != "" {
364				sanitized[key] = value
365			}
366		}
367		return sanitized
368	}
