35	export default function Providers({ children }: ProvidersProps) {
36	  const [isHydrated, setIsHydrated] = useState(false);
37	  const [lastSyncAt, setLastSyncAt] = useState<number | null>(null);
38	  const persistTimerRef = useRef<number | null>(null);
39	
40	  useEffect(() => {
41	    let active = true;
42	    let unsubscribe: (() => void) | undefined;
43	
44	    const schedulePersist = () => {
45	      if (persistTimerRef.current !== null) {
46	        window.clearTimeout(persistTimerRef.current);
47	      }
48	      persistTimerRef.current = window.setTimeout(async () => {
49	        try {
50	          const persistedAt = await persistOfflineQueryCache(queryClient);
51	          if (active && persistedAt) {
52	            setLastSyncAt(persistedAt);
53	          }
54	        } catch {
55	          // Offline persistence is best-effort and should never block app use.
56	        }
57	      }, 250);
58	    };
59	
60	    const replayQueuedMutations = async () => {
61	      try {
62	        await replayOfflineMutations(queryClient);
63	      } catch {
64	        // Replay is best-effort and retried on the next reconnect.
65	      }
66	    };
67	
68	    (async () => {
69	      try {
70	        const snapshot = await loadPersistedQuerySnapshot();
71	        if (active) {
72	          hydrateOfflineQueryCache(queryClient, snapshot);
73	          setLastSyncAt(snapshot?.updatedAt ?? null);
74	        }
75	      } catch {
76	        // If persistence cannot be read we fall back to the live API path.
77	      } finally {
78	        if (active) {
79	          unsubscribe = queryClient.getQueryCache().subscribe(() => {
80	            schedulePersist();
81	          });
82	          window.addEventListener('online', replayQueuedMutations);
83	          void replayQueuedMutations();
84	          setIsHydrated(true);
85	        }
86	      }
87	    })();
88	
89	    return () => {
90	      active = false;
91	      unsubscribe?.();
92	      window.removeEventListener('online', replayQueuedMutations);
93	      if (persistTimerRef.current !== null) {
94	        window.clearTimeout(persistTimerRef.current);
95	      }
96	    };
97	  }, []);
98	
99	  return (
100	    <QueryClientProvider client={queryClient}>
101	      <ThemeProvider theme={theme}>
102	        <CssBaseline />
103	        {isHydrated ? (
104	          <OfflineStatusProvider lastSyncAt={lastSyncAt}>
105	            <AuthProvider>
106	              <NotificationsProvider>
107	                <ErrorBoundary>
108	                  {children}
109	                </ErrorBoundary>
110	              </NotificationsProvider>
111	            </AuthProvider>
112	          </OfflineStatusProvider>
113	        ) : null}
114	      </ThemeProvider>
115	    </QueryClientProvider>
116	  );
117	}
