412	// recordsToRows converts report row maps to a tabular [][]string suitable for
413	// CSV/PDF export. The first row is a sorted header; subsequent rows are values.
414	// Falls back to a minimal metadata row when the records slice is empty.
415	func recordsToRows(reportType string, records []map[string]interface{}) [][]string {
416		if len(records) == 0 {
417			return [][]string{
418				{"report_type", "generated_at"},
419				{reportType, time.Now().UTC().Format(time.RFC3339)},
420			}
421		}
422		headers := make([]string, 0, len(records[0]))
423		for k := range records[0] {
424			headers = append(headers, k)
425		}
426		sort.Strings(headers)
427	
428		table := make([][]string, 0, len(records)+1)
429		table = append(table, headers)
430		for _, rec := range records {
431			row := make([]string, len(headers))
432			for i, h := range headers {
433				if v := rec[h]; v != nil {
434					row[i] = fmt.Sprintf("%v", v)
435				}
436			}
437			table = append(table, row)
438		}
439		return table
440	}
