220	// queryRows executes a query and returns each row as a map[string]interface{}.
221	func (s *ReportServiceImpl) queryRows(ctx context.Context, query string, args ...interface{}) ([]map[string]interface{}, error) {
222		rows, err := s.pool.Query(ctx, query, args...)
223		if err != nil {
224			return nil, err
225		}
226		defer rows.Close()
227	
228		fields := rows.FieldDescriptions()
229		var result []map[string]interface{}
230		for rows.Next() {
231			values, err := rows.Values()
232			if err != nil {
233				return nil, err
234			}
235			row := make(map[string]interface{}, len(fields))
236			for i, field := range fields {
237				row[string(field.Name)] = values[i]
238			}
239			result = append(result, row)
240		}
241		if err := rows.Err(); err != nil {
242			return nil, err
243		}
244		if result == nil {
245			result = []map[string]interface{}{}
246		}
247		return result, nil
248	}
