        entry.payload,
      );
      const serverID = (response as { data?: { id?: string } }).data?.id;
      if (serverID) {
        await setOfflineItemIDMapping(entry.id, serverID);
      }
      return;
    }
    case "update-item": {
      const id = entry.payload.id;
      const body = entry.payload.body;
      if (typeof id !== "string" || !body || typeof body !== "object") {
        return;
      }
      await apiClient.put(`/items/${id}`, body);
      return;
    }
    case "run-export":
      await apiClient.post("/exports", entry.payload);
      return;
    default:
      return;
  }
}

export async function replayOfflineMutations(
  queryClient: QueryClient,
): Promise<number> {
  if (isBrowserOffline()) {
    return 0;
  }

  // loadPendingOfflineMutations already filters out failed entries.
  const queue = await loadPendingOfflineMutations();
  let processed = 0;

  for (const entry of queue) {
    try {
      await executeMutation(entry);
      await removeOfflineMutation(entry.id);
      processed += 1;
    } catch (error) {
      if (isOfflineApiError(error)) {
        // Transient network failure — stop here and retry on next reconnect.
        break;
      }
      // Terminal server error (4xx/5xx): retain the entry in failed state so
      // the operator can review and explicitly dismiss it.
      const message =
        typeof error === "object" && error !== null && "message" in error
          ? String((error as { message?: unknown }).message ?? "replay failed")
          : "replay failed";
      await markOfflineMutationFailed(entry.id, message);
    }
  }

  if (processed > 0) {
    queryClient.invalidateQueries({ queryKey: ["items"] });
    queryClient.invalidateQueries({ queryKey: ["reports"] });
    queryClient.invalidateQueries({ queryKey: ["exports"] });
  }

  // Notify any UI components (e.g. FailedMutationsBanner) that replay has
  // completed so they can refresh their failed-entry count.
  if (typeof window !== "undefined") {
    window.dispatchEvent(new CustomEvent("fitcommerce:mutations-replay"));
  }

  return processed;
}
