22	type inventoryCoordinator struct {
23		items        store.ItemRepository
24		inventory    store.InventoryRepository
25		availability store.AvailabilityWindowRepository
26		blackouts    store.BlackoutWindowRepository
27	}
28	
29	func (c inventoryCoordinator) ensureReservable(ctx context.Context, itemID uuid.UUID, quantity int, now time.Time) (*domain.Item, error) {
30		item, err := c.items.GetByID(ctx, itemID)
31		if err != nil {
32			return nil, err
33		}
34		if item.Status != domain.ItemStatusPublished {
35			return nil, &domain.ErrValidation{Field: "item_id", Message: "item is not available for ordering"}
36		}
37		if quantity < 1 {
38			return nil, &domain.ErrValidation{Field: "quantity", Message: "quantity must be at least 1"}
39		}
40		if item.Quantity < quantity {
41			return nil, &domain.ErrValidation{Field: "quantity", Message: "requested quantity exceeds available stock"}
42		}
43	
44		if c.availability != nil {
45			windows, err := c.availability.ListByItemID(ctx, itemID)
46			if err != nil {
47				return nil, err
48			}
49			if len(windows) > 0 && !timeInAvailabilityWindows(now, windows) {
50				return nil, &domain.ErrValidation{Field: "item_id", Message: "item is outside its availability window"}
51			}
52		}
53	
54		if c.blackouts != nil {
55			blackouts, err := c.blackouts.ListByItemID(ctx, itemID)
56			if err != nil {
57				return nil, err
58			}
59			if timeInBlackoutWindows(now, blackouts) {
60				return nil, &domain.ErrValidation{Field: "item_id", Message: "item is unavailable during a blackout window"}
61			}
62		}
63	
64		return item, nil
65	}
