67	func (c inventoryCoordinator) applyChange(ctx context.Context, itemID uuid.UUID, quantityChange int, reason string, actorID uuid.UUID, now time.Time) error {
68		item, err := c.items.GetByID(ctx, itemID)
69		if err != nil {
70			return err
71		}
72	
73		newQty := item.Quantity + quantityChange
74		if newQty < 0 {
75			return &domain.ErrValidation{Field: "quantity", Message: "inventory change would make quantity negative"}
76		}
77	
78		item.Quantity = newQty
79		item.UpdatedAt = now
80		item.Version++
81		if err := c.items.Update(ctx, item); err != nil {
82			return err
83		}
84	
85		if err := c.inventory.CreateAdjustment(ctx, &domain.InventoryAdjustment{
86			ID:             uuid.New(),
87			ItemID:         itemID,
88			QuantityChange: quantityChange,
89			Reason:         reason,
90			CreatedBy:      actorID,
91			CreatedAt:      now,
92		}); err != nil {
93			return err
94		}
95	
96		return c.inventory.CreateSnapshot(ctx, &domain.InventorySnapshot{
97			ID:         uuid.New(),
98			ItemID:     itemID,
99			Quantity:   newQty,
100			LocationID: item.LocationID,
101			RecordedAt: now,
102		})
103	}
104	
105	func timeInAvailabilityWindows(now time.Time, windows []domain.AvailabilityWindow) bool {
106		for _, window := range windows {
107			if !now.Before(window.StartTime) && now.Before(window.EndTime) {
108				return true
109			}
110		}
111		return false
112	}
113	
114	func timeInBlackoutWindows(now time.Time, windows []domain.BlackoutWindow) bool {
115		for _, window := range windows {
116			if !now.Before(window.StartTime) && now.Before(window.EndTime) {
117				return true
118			}
119		}
120		return false
121	}
