46	// Register creates a new biometric enrollment for the given user. The
47	// templateRef is an opaque reference; raw biometric data never enters the
48	// application layer. The reference is encrypted with AES-256-GCM using the
49	// active biometric encryption key before storage.
50	func (s *BiometricServiceImpl) Register(ctx context.Context, userID uuid.UUID, templateRef string) (*domain.BiometricEnrollment, error) {
51		activeKey, err := s.ensureActiveKey(ctx)
52		if err != nil {
53			return nil, fmt.Errorf("biometric.Register: no active encryption key: %w", err)
54		}
55	
56		aesKey, err := security.DeriveKeyFromRef(activeKey.KeyReference)
57		if err != nil {
58			return nil, fmt.Errorf("biometric.Register: key derivation failed: %w", err)
59		}
60	
61		encrypted, err := security.EncryptAESGCM([]byte(templateRef), aesKey)
62		if err != nil {
63			return nil, fmt.Errorf("biometric.Register: encryption failed: %w", err)
64		}
65	
66		now := time.Now().UTC()
67		enrollment := &domain.BiometricEnrollment{
68			ID:              uuid.New(),
69			UserID:          userID,
70			EncryptedData:   encrypted,
71			EncryptionKeyID: activeKey.ID,
72			CreatedAt:       now,
73			UpdatedAt:       now,
74		}
75	
76		if err := s.biometricRepo.Create(ctx, enrollment); err != nil {
77			return nil, err
78		}
79	
80		_ = s.auditSvc.Log(ctx, "biometric.registered", "biometric_enrollment", enrollment.ID, userID, map[string]interface{}{})
81	
82		return enrollment, nil
83	}
