118	// RotateKey rotates the active biometric envelope key and re-encrypts existing
119	// enrollment references under the new active key inside one transaction.
120	func (s *BiometricServiceImpl) RotateKey(ctx context.Context, performedBy uuid.UUID) (*domain.EncryptionKey, error) {
121		var newKey *domain.EncryptionKey
122	
123		err := withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
124			oldKey, err := s.encKeyRepo.GetActive(txCtx, "biometric")
125			if err != nil && err != domain.ErrNotFound {
126				return err
127			}
128	
129			newKey = &domain.EncryptionKey{
130				ID:           uuid.New(),
131				KeyReference: uuid.New().String(),
132				Purpose:      "biometric",
133				Status:       domain.EncryptionKeyStatusActive,
134				ActivatedAt:  time.Now().UTC(),
135				ExpiresAt:    time.Now().UTC().AddDate(0, 0, s.rotationDays),
136			}
137	
138			var oldAESKey []byte
139			if oldKey != nil && err != domain.ErrNotFound {
140				oldAESKey, err = security.DeriveKeyFromRef(oldKey.KeyReference)
141				if err != nil {
142					return fmt.Errorf("biometric.RotateKey old key derivation failed: %w", err)
143				}
144			}
145	
146			newAESKey, err := security.DeriveKeyFromRef(newKey.KeyReference)
147			if err != nil {
148				return fmt.Errorf("biometric.RotateKey new key derivation failed: %w", err)
149			}
150	
151			if err := s.encKeyRepo.Create(txCtx, newKey); err != nil {
152				return err
153			}
154	
155			enrollments, err := s.biometricRepo.List(txCtx)
156			if err != nil {
157				return err
158			}
159			for i := range enrollments {
160				if len(enrollments[i].EncryptedData) == 0 || oldAESKey == nil {
161					enrollments[i].EncryptionKeyID = newKey.ID
162					enrollments[i].UpdatedAt = time.Now().UTC()
163					if err := s.biometricRepo.Update(txCtx, &enrollments[i]); err != nil {
164						return err
165					}
166					continue
167				}
168	
169				plaintext, err := security.DecryptAESGCM(enrollments[i].EncryptedData, oldAESKey)
170				if err != nil {
171					return fmt.Errorf("biometric.RotateKey decrypt enrollment %s: %w", enrollments[i].ID, err)
172				}
173				reencrypted, err := security.EncryptAESGCM(plaintext, newAESKey)
174				if err != nil {
175					return fmt.Errorf("biometric.RotateKey re-encrypt enrollment %s: %w", enrollments[i].ID, err)
176				}
177	
178				enrollments[i].EncryptedData = reencrypted
179				enrollments[i].EncryptionKeyID = newKey.ID
180				enrollments[i].UpdatedAt = time.Now().UTC()
181				if err := s.biometricRepo.Update(txCtx, &enrollments[i]); err != nil {
182					return err
183				}
184			}
185	
186			if oldKey != nil && err != domain.ErrNotFound {
187				now := time.Now().UTC()
188				oldKey.Status = domain.EncryptionKeyStatusRotated
189				oldKey.RotatedAt = &now
190				if err := s.encKeyRepo.Update(txCtx, oldKey); err != nil {
191					return err
192				}
193			}
194	
195			return s.auditSvc.Log(txCtx, "encryption_key.rotated", "encryption_key", newKey.ID, performedBy, map[string]interface{}{
196				"re_encrypted_enrollments": len(enrollments),
197			})
198		})
199		if err != nil {
200			return nil, err
201		}
202	
203		return newKey, nil
204	}
205	
