46	// GetReportData handles GET /reports/:id/data.
47	func (h *ReportHandler) GetReportData(c echo.Context) error {
48		user, ok := security.GetUserFromContext(c)
49		if !ok {
50			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
51		}
52	
53		id, err := uuid.Parse(c.Param("id"))
54		if err != nil {
55			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid report id"))
56		}
57	
58		// Handler-layer role check: verify access before querying data.
59		report, err := h.svc.GetReport(c.Request().Context(), id)
60		if err != nil {
61			return HandleDomainError(c, err)
62		}
63		allowed := false
64		for _, r := range report.AllowedRoles {
65			if r == user.Role {
66				allowed = true
67				break
68			}
69		}
70		if !allowed {
71			return c.JSON(http.StatusForbidden, NewErrorResponse("FORBIDDEN", "not authorized to access this report"))
72		}
73	
74		filters := make(map[string]string)
75		for k, v := range c.QueryParams() {
76			if len(v) > 0 {
77				filters[k] = v[0]
78			}
79		}
80	
81		// Service enforces role check as a second layer.
82		result, err := h.svc.GetData(c.Request().Context(), id, filters, user.Role)
83		if err != nil {
84			return HandleDomainError(c, err)
85		}
86	
87		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: result})
88	}
