90	// RunExport handles POST /exports.
91	func (h *ReportHandler) RunExport(c echo.Context) error {
92		user, ok := security.GetUserFromContext(c)
93		if !ok {
94			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
95		}
96	
97		var req dto.CreateExportRequest
98		if err := c.Bind(&req); err != nil {
99			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid request body"))
100		}
101		if err := c.Validate(&req); err != nil {
102			return c.JSON(http.StatusUnprocessableEntity, NewErrorResponse("VALIDATION_ERROR", err.Error()))
103		}
104	
105		reportID, err := uuid.Parse(req.ReportID)
106		if err != nil {
107			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid report_id"))
108		}
109	
110		job, err := h.svc.GenerateExport(c.Request().Context(), reportID, domain.ExportFormat(req.Format), req.Parameters, user.ID, user.Role)
111		if err != nil {
112			return HandleDomainError(c, err)
113		}
114	
115		return c.JSON(http.StatusAccepted, dto.SuccessResponse{Data: toExportResponse(job)})
116	}
