127			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
128		}
129	
130		// Service enforces creator-or-admin access.
131		job, err := h.svc.GetExport(c.Request().Context(), id, user.ID, user.Role)
