139	// DownloadExport handles GET /exports/:id/download.
140	func (h *ReportHandler) DownloadExport(c echo.Context) error {
141		user, ok := security.GetUserFromContext(c)
142		if !ok {
143			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
144		}
145	
146		id, err := uuid.Parse(c.Param("id"))
147		if err != nil {
148			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
149		}
150	
151		// Service enforces creator-or-admin access.
152		job, err := h.svc.DownloadExport(c.Request().Context(), id, user.ID, user.Role)
153		if err != nil {
154			return HandleDomainError(c, err)
155		}
156	
157		if job.FilePath == "" {
158			return c.JSON(http.StatusNotFound, NewErrorResponse("NOT_FOUND", "export file not found"))
159		}
160	
161		filename := job.Filename
162		if filename == "" {
163			filename = filepath.Base(job.FilePath)
164		}
165		contentDisposition := mime.FormatMediaType("attachment", map[string]string{"filename": filename})
166		if contentDisposition != "" {
167			c.Response().Header().Set("Content-Disposition", contentDisposition)
168		}
169		if contentType := mime.TypeByExtension(filepath.Ext(filename)); contentType != "" {
170			c.Response().Header().Set("Content-Type", contentType)
171		} else {
172			c.Response().Header().Set("Content-Type", "application/octet-stream")
173		}
174		c.Response().Header().Set("Cache-Control", "no-store")
175	
176		return c.File(job.FilePath)
177	}
