127	func (s *DashboardServiceImpl) memberGrowth(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
128		cur, err := s.countMembers(ctx, locationID, coachID, &curStart, &curEnd)
129		if err != nil {
130			return KPIValue{}, err
131		}
132		prev, err := s.countMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
133		if err != nil {
134			return KPIValue{}, err
135		}
136		return makeKPI(float64(cur), float64(prev), period), nil
137	}
