200	func (s *DashboardServiceImpl) classFillRate(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
201		curSucceeded, err := s.countCampaignsByStatus(ctx, locationID, coachID, "succeeded", &curStart, &curEnd)
202		if err != nil {
