278	func (s *DashboardServiceImpl) countMembersByStatus(ctx context.Context, locationID, coachID *uuid.UUID, status string) (int, error) {
279		q := `SELECT COUNT(*) FROM members WHERE membership_status = $1`
280		args := []interface{}{status}
281		n := 2
282		if locationID != nil {
283			q += fmt.Sprintf(" AND location_id = $%d", n)
284			args = append(args, *locationID)
285			n++
286		}
287		if coachID != nil {
288			q += fmt.Sprintf(" AND location_id = (SELECT location_id FROM coaches WHERE id = $%d)", n)
289			args = append(args, *coachID)
290		}
291		var count int
292		if err := s.pool.QueryRow(ctx, q, args...).Scan(&count); err != nil {
293			return 0, err
294		}
295		return count, nil
296	}
