54	// Create validates lines, persists the purchase order and its lines, and records an audit event.
55	func (s *PurchaseOrderServiceImpl) Create(ctx context.Context, po *domain.PurchaseOrder, lines []domain.PurchaseOrderLine) (*domain.PurchaseOrder, error) {
56		for i := range lines {
57			if _, err := s.itemRepo.GetByID(ctx, lines[i].ItemID); err != nil {
58				if errors.Is(err, domain.ErrNotFound) {
59					return nil, fmt.Errorf("procurement_service.Create item %s not found: %w", lines[i].ItemID, domain.ErrNotFound)
60				}
61				return nil, fmt.Errorf("procurement_service.Create get item: %w", err)
62			}
63		}
64	
65		now := time.Now().UTC()
66		po.ID = uuid.New()
67		po.Status = domain.POStatusCreated
68		po.CreatedAt = now
69		po.Version = 1
70	
71		var total float64
72		for _, line := range lines {
73			total += float64(line.OrderedQuantity) * line.OrderedUnitPrice
74		}
75		po.TotalAmount = total
76	
77		if err := withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
78			if err := s.poRepo.Create(txCtx, po); err != nil {
79				return fmt.Errorf("procurement_service.Create po: %w", err)
80			}
81			for i := range lines {
82				lines[i].ID = uuid.New()
83				lines[i].PurchaseOrderID = po.ID
84				if err := s.lineRepo.Create(txCtx, &lines[i]); err != nil {
85					return fmt.Errorf("procurement_service.Create line: %w", err)
86				}
87			}
88			return s.audit.Log(txCtx, "po.created", "purchase_order", po.ID, po.CreatedBy, map[string]interface{}{
89				"supplier_id":  po.SupplierID.String(),
90				"total_amount": po.TotalAmount,
91				"line_count":   len(lines),
92			})
93		}); err != nil {
94			return nil, err
95		}
96		return po, nil
97	}
