147	// Receive transitions a purchase order to received, records received quantities/prices,
148	// generates variance records, inventory adjustments, and landed cost entries.
149	func (s *PurchaseOrderServiceImpl) Receive(ctx context.Context, id uuid.UUID, receivedLines []ReceivedLineInput, actorID uuid.UUID) error {
150		now := time.Now().UTC()
151		return withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
152			po, err := s.poRepo.GetByID(txCtx, id)
153			if err != nil {
154				if errors.Is(err, domain.ErrNotFound) {
155					return err
156				}
157				return fmt.Errorf("procurement_service.Receive get po: %w", err)
158			}
159			existingLines, err := s.lineRepo.ListByPOID(txCtx, id)
160			if err != nil {
161				return fmt.Errorf("procurement_service.Receive list lines: %w", err)
162			}
163			if err := domain.TransitionPO(po, domain.POStatusReceived); err != nil {
164				return err
165			}
166			po.ReceivedAt = &now
167			if err := s.poRepo.Update(txCtx, po); err != nil {
168				return fmt.Errorf("procurement_service.Receive update po: %w", err)
169			}
170	
171			lineMap := make(map[uuid.UUID]*domain.PurchaseOrderLine, len(existingLines))
172			for i := range existingLines {
173				lineMap[existingLines[i].ID] = &existingLines[i]
174			}
175			quarter := strconv.Itoa((int(now.Month())-1)/3 + 1)
176			period := now.UTC().Format("2006") + "-Q" + quarter
177			dueDate := domain.CalculateResolutionDueDate(now)
178	
179			for _, receivedLine := range receivedLines {
180				line, ok := lineMap[receivedLine.POLineID]
181				if !ok {
182					return fmt.Errorf("procurement_service.Receive: line %s not found on PO", receivedLine.POLineID)
183				}
184				line.ReceivedQuantity = &receivedLine.ReceivedQuantity
185				line.ReceivedUnitPrice = &receivedLine.ReceivedUnitPrice
186				if err := s.lineRepo.Update(txCtx, line); err != nil {
187					return fmt.Errorf("procurement_service.Receive update line: %w", err)
188				}
189	
190				if receivedLine.ReceivedQuantity != line.OrderedQuantity {
191					var varType domain.VarianceType
192					if receivedLine.ReceivedQuantity < line.OrderedQuantity {
193						varType = domain.VarianceTypeShortage
194					} else {
195						varType = domain.VarianceTypeOverage
196					}
197					expected := float64(line.OrderedQuantity)
198					actual := float64(receivedLine.ReceivedQuantity)
199					diff := actual - expected
200					if err := s.varianceRepo.Create(txCtx, &domain.VarianceRecord{
201						ID:                uuid.New(),
202						POLineID:          line.ID,
203						Type:              varType,
204						ExpectedValue:     expected,
205						ActualValue:       actual,
206						DifferenceAmount:  diff,
207						Status:            domain.VarianceStatusOpen,
208						ResolutionDueDate: dueDate,
209						ResolvedAt:        nil,
210						ResolutionNotes:   "",
211						CreatedAt:         now,
212					}); err != nil {
213						return fmt.Errorf("procurement_service.Receive create quantity variance: %w", err)
214					}
215				}
216	
217				if math.Abs(receivedLine.ReceivedUnitPrice-line.OrderedUnitPrice) > 0.0001 {
218					expected := line.OrderedUnitPrice
219					actual := receivedLine.ReceivedUnitPrice
220					diff := actual - expected
221					if err := s.varianceRepo.Create(txCtx, &domain.VarianceRecord{
222						ID:                uuid.New(),
223						POLineID:          line.ID,
224						Type:              domain.VarianceTypePriceDifference,
225						ExpectedValue:     expected,
226						ActualValue:       actual,
227						DifferenceAmount:  diff,
228						Status:            domain.VarianceStatusOpen,
229						ResolutionDueDate: dueDate,
230						ResolvedAt:        nil,
231						ResolutionNotes:   "",
232						CreatedAt:         now,
233					}); err != nil {
234						return fmt.Errorf("procurement_service.Receive create price variance: %w", err)
235					}
236				}
237	
238				if err := s.inventoryCoordinator().applyChange(txCtx, line.ItemID, receivedLine.ReceivedQuantity, "po-receipt", actorID, now); err != nil {
239					return fmt.Errorf("procurement_service.Receive inventory: %w", err)
240				}
241				rawAmount := float64(receivedLine.ReceivedQuantity) * receivedLine.ReceivedUnitPrice
242				if err := s.landedCostRepo.Create(txCtx, &domain.LandedCostEntry{
243					ID:               uuid.New(),
244					ItemID:           line.ItemID,
245					PurchaseOrderID:  po.ID,
246					POLineID:         line.ID,
247					Period:           period,
248					CostComponent:    "unit_cost",
249					RawAmount:        rawAmount,
250					AllocatedAmount:  rawAmount,
251					AllocationMethod: "direct",
252					CreatedAt:        now,
253				}); err != nil {
254					return fmt.Errorf("procurement_service.Receive create landed cost: %w", err)
255				}
256			}
257	
258			if err := s.audit.Log(txCtx, "po.received", "purchase_order", po.ID, actorID, map[string]interface{}{
259				"received_at": now.Format(time.RFC3339),
260				"line_count":  len(receivedLines),
261			}); err != nil {
262				slog.Default().Warn("audit log failed", "event", "po.received", "error", err)
263				return err
264			}
265			return nil
266		})
267	}
