269	// Return transitions a purchase order to the returned status.
270	func (s *PurchaseOrderServiceImpl) Return(ctx context.Context, id uuid.UUID) error {
271		return withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
272			po, err := s.poRepo.GetByID(txCtx, id)
273			if err != nil {
274				if errors.Is(err, domain.ErrNotFound) {
275					return err
276				}
277				return fmt.Errorf("procurement_service.Return get: %w", err)
278			}
279			if err := domain.TransitionPO(po, domain.POStatusReturned); err != nil {
280				return err
281			}
282			lines, err := s.lineRepo.ListByPOID(txCtx, id)
283			if err != nil {
284				return fmt.Errorf("procurement_service.Return lines: %w", err)
285			}
286			now := time.Now().UTC()
287			for _, line := range lines {
288				if line.ReceivedQuantity != nil && *line.ReceivedQuantity > 0 {
289					if err := s.inventoryCoordinator().applyChange(txCtx, line.ItemID, -*line.ReceivedQuantity, "po-return", domain.SystemActorID, now); err != nil {
290						return err
291					}
292				}
293			}
294			if err := s.poRepo.Update(txCtx, po); err != nil {
295				return fmt.Errorf("procurement_service.Return update: %w", err)
296			}
297			if err := s.audit.Log(txCtx, "po.returned", "purchase_order", po.ID, domain.SystemActorID, nil); err != nil {
298				slog.Default().Warn("audit log failed", "event", "po.returned", "error", err)
299				return err
300			}
301			return nil
302		})
303	}
