160	func (j *BiometricKeyRotationJob) ensureKeyState(ctx context.Context) error {
161		key, err := j.svc.GetActiveKey(ctx)
162		if errors.Is(err, domain.ErrNotFound) {
163			rotated, rotateErr := j.svc.RotateKey(ctx, domain.SystemActorID)
164			if rotateErr != nil {
165				return rotateErr
166			}
167			j.logger.Info("bootstrapped biometric encryption key", "key_id", rotated.ID)
168			return nil
169		}
170		if err != nil {
171			return err
172		}
173	
174		if key.NeedsRotation(j.rotationDays) || time.Now().UTC().After(key.ExpiresAt) {
175			rotated, rotateErr := j.svc.RotateKey(ctx, domain.SystemActorID)
176			if rotateErr != nil {
177				return rotateErr
178			}
179			j.logger.Info("rotated biometric encryption key", "key_id", rotated.ID)
180		}
181	
182		return nil
183	}
