15	  const [failedMutations, setFailedMutations] = useState<OfflineMutationEntry[]>([]);
16	
17	  useEffect(() => {
18	    loadPendingOfflineMutations().then((mutations) => {
19	      setFailedMutations(mutations.filter((m) => m.status === 'failed'));
20	    });
21	  }, [isOnline]);
22	
23	  const dismiss = async (id: string) => {
24	    await removeOfflineMutation(id);
25	    setFailedMutations((prev) => prev.filter((m) => m.id !== id));
26	  };
27	
28	  if (failedMutations.length === 0) {
29	    return null;
30	  }
31	
32	  return (
33	    <Alert severity="error" square>
34	      <Typography variant="body2" fontWeight={600} gutterBottom>
35	        {failedMutations.length} queued action{failedMutations.length > 1 ? 's' : ''} failed to sync.
36	      </Typography>
37	      {failedMutations.map((entry) => (
38	        <Box
39	          key={entry.id}
40	          sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 1, mt: 0.5 }}
