14	
15	// DashboardHandler handles HTTP requests for the dashboard KPI endpoint.
16	type DashboardHandler struct {
17		svc application.DashboardService
18	}
19	
20	// NewDashboardHandler creates a DashboardHandler backed by the given service.
21	func NewDashboardHandler(svc application.DashboardService) *DashboardHandler {
22		return &DashboardHandler{svc: svc}
23	}
24	
25	// GetKPIs handles GET /api/v1/dashboard/kpis.
26	// Optional query params: location_id, period, coach_id, category, from, to.
27	func (h *DashboardHandler) GetKPIs(c echo.Context) error {
28		user, ok := security.GetUserFromContext(c)
29		if !ok {
30			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
31		}
32	
33		var locationID *uuid.UUID
34		if v := c.QueryParam("location_id"); v != "" {
35			id, err := uuid.Parse(v)
36			if err != nil {
37				return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid location_id"))
38			}
39			locationID = &id
40		}
41	
42		// Coaches are scoped to their assigned location. Override any caller-supplied
43		// location_id with the user's own to prevent cross-location data access.
44		if user.Role == domain.UserRoleCoach {
45			locationID = user.LocationID
46		}
47	
48		period := c.QueryParam("period")
49		if period == "" {
50			period = "monthly"
51		}
52	
53		var coachID *uuid.UUID
54		if v := c.QueryParam("coach_id"); v != "" {
55			id, err := uuid.Parse(v)
56			if err != nil {
57				return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid coach_id"))
58			}
59			coachID = &id
60		}
61	
62		category := c.QueryParam("category")
63		from := c.QueryParam("from")
64		to := c.QueryParam("to")
65	
66		kpis, err := h.svc.GetKPIs(c.Request().Context(), locationID, period, coachID, category, from, to)
67		if err != nil {
68			return HandleDomainError(c, err)
69		}
70	
71		resp := dto.KPIDashboardResponse{
72			MemberGrowth:      toKPIMetric(kpis.MemberGrowth),
73			Churn:             toKPIMetric(kpis.Churn),
74			RenewalRate:       toKPIMetric(kpis.RenewalRate),
75			Engagement:        toKPIMetric(kpis.Engagement),
76			ClassFillRate:     toKPIMetric(kpis.ClassFillRate),
77			CoachProductivity: toKPIMetric(kpis.CoachProductivity),
78		}
79		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: resp})
80	}
81	
82	func toKPIMetric(v application.KPIValue) dto.KPIMetric {
83		return dto.KPIMetric{
84			Value:         v.Value,
85			PreviousValue: v.PreviousValue,
86			ChangePercent: v.ChangePercent,
87			Period:        v.Period,
88		}
89	}
