96	// RunExport handles POST /exports.
97	func (h *ReportHandler) RunExport(c echo.Context) error {
98		user, ok := security.GetUserFromContext(c)
99		if !ok {
100			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
101		}
102	
103		var req dto.CreateExportRequest
104		if err := c.Bind(&req); err != nil {
105			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid request body"))
106		}
107		if err := c.Validate(&req); err != nil {
108			return c.JSON(http.StatusUnprocessableEntity, NewErrorResponse("VALIDATION_ERROR", err.Error()))
109		}
110	
111		reportID, err := uuid.Parse(req.ReportID)
112		if err != nil {
113			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid report_id"))
114		}
115	
116		job, err := h.svc.GenerateExport(c.Request().Context(), reportID, domain.ExportFormat(req.Format), req.Parameters, user.ID, user.Role)
117		if err != nil {
118			return HandleDomainError(c, err)
119		}
120	
121		return c.JSON(http.StatusAccepted, dto.SuccessResponse{Data: toExportResponse(job)})
122	}
123	
124	// GetExport handles GET /exports/:id.
125	func (h *ReportHandler) GetExport(c echo.Context) error {
126		user, ok := security.GetUserFromContext(c)
127		if !ok {
128			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
129		}
130	
131		id, err := uuid.Parse(c.Param("id"))
132		if err != nil {
133			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
134		}
135	
136		// Service enforces creator-or-admin access.
137		job, err := h.svc.GetExport(c.Request().Context(), id, user.ID, user.Role)
138		if err != nil {
139			return HandleDomainError(c, err)
140		}
141	
142		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: toExportResponse(job)})
143	}
144	
145	// DownloadExport handles GET /exports/:id/download.
146	func (h *ReportHandler) DownloadExport(c echo.Context) error {
147		user, ok := security.GetUserFromContext(c)
148		if !ok {
149			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
150		}
151	
152		id, err := uuid.Parse(c.Param("id"))
153		if err != nil {
154			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
155		}
156	
157		// Service enforces creator-or-admin access.
158		job, err := h.svc.DownloadExport(c.Request().Context(), id, user.ID, user.Role)
159		if err != nil {
160			return HandleDomainError(c, err)
161		}
162	
163		if job.FilePath == "" {
164			return c.JSON(http.StatusNotFound, NewErrorResponse("NOT_FOUND", "export file not found"))
165		}
166	
167		filename := job.Filename
168		if filename == "" {
169			filename = filepath.Base(job.FilePath)
170		}
171		contentDisposition := mime.FormatMediaType("attachment", map[string]string{"filename": filename})
172		if contentDisposition != "" {
173			c.Response().Header().Set("Content-Disposition", contentDisposition)
174		}
175		if contentType := mime.TypeByExtension(filepath.Ext(filename)); contentType != "" {
176			c.Response().Header().Set("Content-Type", contentType)
177		} else {
178			c.Response().Header().Set("Content-Type", "application/octet-stream")
179		}
180		c.Response().Header().Set("Cache-Control", "no-store")
181	
182		return c.File(job.FilePath)
183	}
