75	function openDatabase(): Promise<IDBDatabase> {
76	  return new Promise((resolve, reject) => {
77	    const request = window.indexedDB.open(DB_NAME, 1);
78	    request.onerror = () => reject(request.error);
79	    request.onupgradeneeded = () => {
80	      const database = request.result;
81	      if (!database.objectStoreNames.contains(STORE_NAME)) {
82	        database.createObjectStore(STORE_NAME);
83	      }
84	    };
85	    request.onsuccess = () => resolve(request.result);
86	  });
87	}
88	
89	async function readStoreValue<T>(key: string): Promise<T | null> {
90	  const database = await openDatabase();
91	  return new Promise((resolve, reject) => {
92	    const transaction = database.transaction(STORE_NAME, "readonly");
93	    const store = transaction.objectStore(STORE_NAME);
94	    const request = store.get(key);
95	    request.onerror = () => reject(request.error);
96	    request.onsuccess = () =>
97	      resolve((request.result as T | undefined) ?? null);
98	    transaction.oncomplete = () => database.close();
99	    transaction.onerror = () => reject(transaction.error);
100	  });
101	}
102	
103	async function writeStoreValue<T>(key: string, value: T): Promise<void> {
104	  const database = await openDatabase();
105	  return new Promise((resolve, reject) => {
106	    const transaction = database.transaction(STORE_NAME, "readwrite");
107	    const store = transaction.objectStore(STORE_NAME);
108	    const request = store.put(value, key);
109	    request.onerror = () => reject(request.error);
110	    transaction.oncomplete = () => {
111	      database.close();
112	      resolve();
113	    };
114	    transaction.onerror = () => reject(transaction.error);
115	  });
116	}
