118	function isOfflineCacheableQuery(query: Query): boolean {
119	  return (
120	    query.state.status === "success" &&
121	    isOfflineCacheableQueryKey(query.queryKey)
122	  );
123	}
124	
125	export function isOfflineCacheableQueryKey(queryKey: QueryKey): boolean {
126	  const root = Array.isArray(queryKey) ? queryKey[0] : undefined;
127	  return typeof root === "string" && OFFLINE_QUERY_ROOTS.has(root);
128	}
