130	export async function loadPersistedQuerySnapshot(): Promise<PersistedQuerySnapshot | null> {
131	  if (typeof window === "undefined" || !("indexedDB" in window)) {
132	    return null;
133	  }
134	  const snapshot =
135	    await readStoreValue<PersistedQuerySnapshot>(QUERY_CACHE_KEY);
136	  if (!snapshot || snapshot.version !== QUERY_CACHE_VERSION) {
137	    return null;
138	  }
139	  return snapshot;
140	}
