142	export function hydrateOfflineQueryCache(
143	  queryClient: QueryClient,
144	  snapshot: PersistedQuerySnapshot | null,
145	): void {
146	  if (!snapshot) {
147	    return;
148	  }
149	  hydrate(queryClient, snapshot.state);
150	}
151	
152	export async function persistOfflineQueryCache(
153	  queryClient: QueryClient,
154	): Promise<number | null> {
155	  if (typeof window === "undefined" || !("indexedDB" in window)) {
156	    return null;
157	  }
158	
159	  const snapshot: PersistedQuerySnapshot = {
160	    version: QUERY_CACHE_VERSION,
161	    updatedAt: Date.now(),
162	    state: dehydrate(queryClient, {
163	      shouldDehydrateQuery: isOfflineCacheableQuery,
164	    }),
165	  };
166	
167	  await writeStoreValue(QUERY_CACHE_KEY, snapshot);
168	  return snapshot.updatedAt;
169	}
