171	// loadAllOfflineMutations loads the full queue regardless of status. Used
172	// internally by write operations that must see both pending and failed entries.
173	async function loadAllOfflineMutations(): Promise<OfflineMutationEntry[]> {
174	  if (typeof window === "undefined" || !("indexedDB" in window)) {
175	    return [];
176	  }
177	  const persisted =
178	    await readStoreValue<PersistedMutationQueue>(MUTATION_QUEUE_KEY);
179	  if (!persisted || persisted.version !== MUTATION_QUEUE_VERSION) {
180	    return [];
181	  }
182	  return persisted.mutations;
183	}
184	
185	// loadPendingOfflineMutations returns only entries that have not yet been
186	// permanently failed. Entries with no status are treated as "pending" for
187	// backwards compatibility with any data written before the status field was
188	// introduced.
189	export async function loadPendingOfflineMutations(): Promise<
190	  OfflineMutationEntry[]
191	> {
192	  const all = await loadAllOfflineMutations();
193	  return all.filter((e) => !e.status || e.status === "pending");
194	}
195	
196	// loadFailedOfflineMutations returns only entries marked as terminal failures.
197	export async function loadFailedOfflineMutations(): Promise<
198	  OfflineMutationEntry[]
199	> {
200	  const all = await loadAllOfflineMutations();
201	  return all.filter((e) => e.status === "failed");
202	}
203	
204	export async function enqueueOfflineMutation(
205	  entry: OfflineMutationEntry,
206	): Promise<void> {
207	  if (typeof window === "undefined" || !("indexedDB" in window)) {
208	    return;
209	  }
210	
211	  const existing = await loadAllOfflineMutations();
212	  const queue: PersistedMutationQueue = {
213	    version: MUTATION_QUEUE_VERSION,
214	    updatedAt: Date.now(),
215	    mutations: [...existing, { ...entry, status: entry.status ?? "pending" }],
216	  };
217	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
218	}
