220	// markOfflineMutationFailed marks a queued entry as permanently failed with an
221	// error message. The entry is retained in the queue so operators can review and
222	// explicitly dismiss it via clearFailedOfflineMutations.
223	export async function markOfflineMutationFailed(
224	  id: string,
225	  message: string,
226	): Promise<void> {
227	  if (typeof window === "undefined" || !("indexedDB" in window)) {
228	    return;
229	  }
230	
231	  const existing = await loadAllOfflineMutations();
232	  const now = Date.now();
233	  const queue: PersistedMutationQueue = {
234	    version: MUTATION_QUEUE_VERSION,
235	    updatedAt: now,
236	    mutations: existing.map((entry) => {
237	      if (entry.id !== id) return entry;
238	      return {
239	        ...entry,
240	        status: "failed" as const,
241	        updatedAt: now,
242	        lastError: message,
243	      };
244	    }),
245	  };
246	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
247	}
248	
249	// clearFailedOfflineMutations removes all failed entries. Call this only after
250	// the operator has explicitly acknowledged and dismissed the failures.
251	export async function clearFailedOfflineMutations(): Promise<void> {
252	  if (typeof window === "undefined" || !("indexedDB" in window)) {
253	    return;
254	  }
255	
256	  const existing = await loadAllOfflineMutations();
257	  const queue: PersistedMutationQueue = {
258	    version: MUTATION_QUEUE_VERSION,
259	    updatedAt: Date.now(),
260	    mutations: existing.filter((e) => e.status !== "failed"),
261	  };
262	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
263	}
264	
265	export async function removeOfflineMutation(id: string): Promise<void> {
266	  if (typeof window === "undefined" || !("indexedDB" in window)) {
267	    return;
268	  }
269	
270	  const existing = await loadAllOfflineMutations();
271	  const queue: PersistedMutationQueue = {
272	    version: MUTATION_QUEUE_VERSION,
273	    updatedAt: Date.now(),
274	    mutations: existing.filter((entry) => entry.id !== id),
275	  };
276	  await writeStoreValue(MUTATION_QUEUE_KEY, queue);
277	}
