241		t.Helper()
242	
243		var bodyReader io.Reader
244		if body != nil {
245			payload, err := json.Marshal(body)
246			if err != nil {
247				t.Fatalf("marshal request body: %v", err)
248			}
249			bodyReader = bytes.NewReader(payload)
250		}
251	
252		req, err := http.NewRequest(method, a.server.URL+path, bodyReader)
253		if err != nil {
254			t.Fatalf("create request: %v", err)
255		}
256		if body != nil {
257			req.Header.Set("Content-Type", "application/json")
258		}
259		for _, cookie := range cookies {
260			req.AddCookie(cookie)
261		}
262	
263		resp, err := a.client.Do(req)
264		if err != nil {
265			t.Fatalf("do request %s %s: %v", method, path, err)
266		}
267		defer resp.Body.Close()
268	
269		respBody, err := io.ReadAll(resp.Body)
270		if err != nil {
271			t.Fatalf("read response body: %v", err)
272		}
273	
274		// Wrap the real HTTP response in a ResponseRecorder so all existing
275		// assertions (rec.Code, rec.Body.Bytes(), rec.Header()) stay unchanged.
276		return &httptest.ResponseRecorder{
277			Code:      resp.StatusCode,
278			HeaderMap: resp.Header,
279			Body:      bytes.NewBuffer(respBody),
280		}
281	}
