1	import type { QueryClient } from "@tanstack/react-query";
2	import { apiClient, isOfflineApiError } from "@/lib/api-client";
3	import {
4	  loadPendingOfflineMutations,
5	  markOfflineMutationFailed,
6	  removeOfflineMutation,
7	  setOfflineItemIDMapping,
8	  type OfflineMutationEntry,
9	} from "@/lib/offline-cache";
10	
11	function isBrowserOffline(): boolean {
12	  return typeof navigator !== "undefined" && !navigator.onLine;
13	}
14	
15	async function executeMutation(entry: OfflineMutationEntry): Promise<void> {
16	  switch (entry.type) {
17	    case "create-item": {
18	      const temporaryID =
19	        typeof entry.payload.__offline_temp_id === "string"
20	          ? entry.payload.__offline_temp_id
21	          : undefined;
22	      const payload = { ...entry.payload };
23	      delete payload.__offline_temp_id;
24	
25	      const response = await apiClient.post<
26	        Record<string, unknown> | { data?: Record<string, unknown> }
27	      >("/items", payload);
28	
29	      const responseRecord = response as Record<string, unknown>;
30	      const topLevelID = responseRecord["id"];
31	      const nestedData = responseRecord["data"];
32	
33	      const serverID =
34	        (typeof topLevelID === "string" ? topLevelID : undefined) ??
35	        (typeof nestedData === "object" &&
36	        nestedData &&
37	        typeof (nestedData as Record<string, unknown>).id === "string"
38	          ? ((nestedData as Record<string, unknown>).id as string)
39	          : undefined);
40	
41	      if (temporaryID && serverID) {
42	        await setOfflineItemIDMapping(temporaryID, serverID);
43	      }
44	      return;
45	    }
46	    case "update-item": {
47	      const id = entry.payload.id;
48	      const body = entry.payload.body;
49	      if (typeof id !== "string" || !body || typeof body !== "object") {
50	        return;
51	      }
52	      await apiClient.put(`/items/${id}`, body);
53	      return;
54	    }
55	    case "run-export":
56	      await apiClient.post("/exports", entry.payload);
57	      return;
58	    default:
59	      return;
60	  }
61	}
62	
63	export async function replayOfflineMutations(
64	  queryClient: QueryClient,
65	): Promise<number> {
66	  if (isBrowserOffline()) {
67	    return 0;
68	  }
69	
70	  const queue = await loadPendingOfflineMutations();
71	  let processed = 0;
72	
73	  for (const entry of queue) {
74	    if (entry.status === "failed") {
75	      continue;
76	    }
77	
78	    try {
79	      await executeMutation(entry);
80	      await removeOfflineMutation(entry.id);
81	      processed += 1;
82	    } catch (error) {
83	      if (isOfflineApiError(error)) {
84	        break;
85	      }
86	
87	      const message =
88	        typeof error === "object" && error && "message" in error
89	          ? String((error as { message?: unknown }).message ?? "replay failed")
90	          : "replay failed";
91	      await markOfflineMutationFailed(entry.id, message);
92	    }
93	  }
94	
95	  if (processed > 0) {
96	    queryClient.invalidateQueries({ queryKey: ["items"] });
97	    queryClient.invalidateQueries({ queryKey: ["reports"] });
98	    queryClient.invalidateQueries({ queryKey: ["exports"] });
99	  }
100	
101	  return processed;
102	}
