1	import type { QueryClient } from "@tanstack/react-query";
2	import { apiClient, isOfflineApiError } from "@/lib/api-client";
3	import {
4	  loadPendingOfflineMutations,
5	  markOfflineMutationFailed,
6	  removeOfflineMutation,
7	  setOfflineItemIDMapping,
8	  type OfflineMutationEntry,
9	} from "@/lib/offline-cache";
10	
11	function isBrowserOffline(): boolean {
12	  return typeof navigator !== "undefined" && !navigator.onLine;
13	}
14	
15	async function executeMutation(entry: OfflineMutationEntry): Promise<void> {
16	  switch (entry.type) {
17	    case "create-item": {
18	      const temporaryID =
19	        typeof entry.payload.__offline_temp_id === "string"
20	          ? entry.payload.__offline_temp_id
21	          : undefined;
22	      const payload = { ...entry.payload };
23	      delete payload.__offline_temp_id;
24	
25	      const response = await apiClient.post<
26	        Record<string, unknown> | { data?: Record<string, unknown> }
27	      >("/items", payload);
28	
29	      const responseRecord = response as Record<string, unknown>;
30	      const topLevelID = responseRecord["id"];
31	      const nestedData = responseRecord["data"];
32	
33	      const serverID =
34	        (typeof topLevelID === "string" ? topLevelID : undefined) ??
35	        (typeof nestedData === "object" &&
36	        nestedData &&
37	        typeof (nestedData as Record<string, unknown>).id === "string"
38	          ? ((nestedData as Record<string, unknown>).id as string)
39	          : undefined);
40	
41	      if (temporaryID && serverID) {
42	        await setOfflineItemIDMapping(temporaryID, serverID);
43	      }
44	      return;
45	    }
46	    case "update-item": {
47	      const id = entry.payload.id;
48	      const body = entry.payload.body;
49	      if (typeof id !== "string" || !body || typeof body !== "object") {
50	        return;
51	      }
52	      await apiClient.put(`/items/${id}`, body);
53	      return;
54	    }
55	    case "run-export":
56	      await apiClient.post("/exports", entry.payload);
57	      return;
58	    case "cancel-order":
59	      await apiClient.post(`/orders/${entry.payload.id}/cancel`, {});
60	      return;
61	    case "pay-order":
62	      await apiClient.post(`/orders/${entry.payload.id}/pay`, {
63	        settlement_marker: entry.payload.settlementMarker,
64	      });
65	      return;
66	    case "join-campaign":
67	      await apiClient.post(`/campaigns/${entry.payload.id}/join`, {
68	        quantity: entry.payload.quantity,
69	      });
70	      return;
71	    case "cancel-campaign":
72	      await apiClient.post(`/campaigns/${entry.payload.id}/cancel`, {});
73	      return;
74	    case "create-po":
75	      await apiClient.post("/purchase-orders", entry.payload);
76	      return;
77	    case "approve-po":
78	      await apiClient.post(`/purchase-orders/${entry.payload.id}/approve`, {});
79	      return;
80	    case "receive-po":
81	      await apiClient.post(
82	        `/purchase-orders/${entry.payload.id}/receive`,
83	        entry.payload.body,
84	      );
85	      return;
86	    case "void-po":
87	      await apiClient.post(`/purchase-orders/${entry.payload.id}/void`, {});
88	      return;
89	    default:
90	      return;
91	  }
92	}
93	
94	export async function replayOfflineMutations(
95	  queryClient: QueryClient,
96	): Promise<number> {
97	  if (isBrowserOffline()) {
98	    return 0;
99	  }
100	
101	  const queue = await loadPendingOfflineMutations();
102	  let processed = 0;
103	
104	  for (const entry of queue) {
105	    if (entry.status === "failed") {
106	      continue;
107	    }
108	
109	    try {
110	      await executeMutation(entry);
111	      await removeOfflineMutation(entry.id);
112	      processed += 1;
113	    } catch (error) {
114	      if (isOfflineApiError(error)) {
115	        break;
116	      }
117	
118	      const message =
119	        typeof error === "object" && error && "message" in error
120	          ? String((error as { message?: unknown }).message ?? "replay failed")
121	          : "replay failed";
122	      await markOfflineMutationFailed(entry.id, message);
123	    }
124	  }
125	
126	  if (processed > 0) {
127	    queryClient.invalidateQueries({ queryKey: ["items"] });
128	    queryClient.invalidateQueries({ queryKey: ["orders"] });
129	    queryClient.invalidateQueries({ queryKey: ["campaigns"] });
130	    queryClient.invalidateQueries({ queryKey: ["purchase-orders"] });
131	    queryClient.invalidateQueries({ queryKey: ["reports"] });
132	    queryClient.invalidateQueries({ queryKey: ["exports"] });
133	  }
134	
135	  return processed;
136	}
