17	// ReportHandler handles HTTP requests for report and export endpoints.
18	type ReportHandler struct {
19		svc application.ReportService
20	}
21	
22	// NewReportHandler creates a ReportHandler backed by the given service.
23	func NewReportHandler(svc application.ReportService) *ReportHandler {
24		return &ReportHandler{svc: svc}
25	}
26	
27	// ListReports handles GET /reports.
28	func (h *ReportHandler) ListReports(c echo.Context) error {
29		user, ok := security.GetUserFromContext(c)
30		if !ok {
31			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
32		}
33	
34		reports, err := h.svc.List(c.Request().Context(), user.Role)
35		if err != nil {
36			return HandleDomainError(c, err)
37		}
38	
39		resp := make([]dto.ReportResponse, len(reports))
40		for i := range reports {
41			resp[i] = toReportResponse(&reports[i])
42		}
43		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: resp})
44	}
45	
46	// GetReportData handles GET /reports/:id/data.
47	func (h *ReportHandler) GetReportData(c echo.Context) error {
48		user, ok := security.GetUserFromContext(c)
49		if !ok {
50			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
51		}
52	
53		id, err := uuid.Parse(c.Param("id"))
54		if err != nil {
55			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid report id"))
56		}
57	
58		// Handler-layer role check: verify access before querying data.
59		report, err := h.svc.GetReport(c.Request().Context(), id)
60		if err != nil {
61			return HandleDomainError(c, err)
62		}
63		allowed := false
64		for _, r := range report.AllowedRoles {
65			if r == user.Role {
66				allowed = true
67				break
68			}
69		}
70		if !allowed {
71			return c.JSON(http.StatusForbidden, NewErrorResponse("FORBIDDEN", "not authorized to access this report"))
72		}
73	
74		filters := make(map[string]string)
75		for k, v := range c.QueryParams() {
76			if len(v) > 0 {
77				filters[k] = v[0]
78			}
79		}
80	
81		// Coaches are scoped to their assigned location. A coach with no assigned
82		// location cannot be safely scoped, so deny access entirely.
83		if user.Role == domain.UserRoleCoach {
84			if user.LocationID == nil {
85				return c.JSON(http.StatusForbidden, NewErrorResponse("FORBIDDEN", "coach account has no assigned location"))
86			}
87			filters["location_id"] = user.LocationID.String()
88		}
89	
90		// Service enforces role check as a second layer.
91		result, err := h.svc.GetData(c.Request().Context(), id, filters, user.Role)
92		if err != nil {
93			return HandleDomainError(c, err)
94		}
95	
96		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: result})
97	}
98	
99	// RunExport handles POST /exports.
100	func (h *ReportHandler) RunExport(c echo.Context) error {
101		user, ok := security.GetUserFromContext(c)
102		if !ok {
103			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
104		}
105	
106		var req dto.CreateExportRequest
107		if err := c.Bind(&req); err != nil {
108			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid request body"))
109		}
110		if err := c.Validate(&req); err != nil {
111			return c.JSON(http.StatusUnprocessableEntity, NewErrorResponse("VALIDATION_ERROR", err.Error()))
112		}
113	
114		reportID, err := uuid.Parse(req.ReportID)
115		if err != nil {
116			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid report_id"))
117		}
118	
119		job, err := h.svc.GenerateExport(c.Request().Context(), reportID, domain.ExportFormat(req.Format), req.Parameters, user.ID, user.Role)
120		if err != nil {
121			return HandleDomainError(c, err)
122		}
123	
124		return c.JSON(http.StatusAccepted, dto.SuccessResponse{Data: toExportResponse(job)})
125	}
126	
127	// GetExport handles GET /exports/:id.
128	func (h *ReportHandler) GetExport(c echo.Context) error {
129		user, ok := security.GetUserFromContext(c)
130		if !ok {
131			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
132		}
133	
134		id, err := uuid.Parse(c.Param("id"))
135		if err != nil {
136			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
137		}
138	
139		// Service enforces creator-or-admin access.
140		job, err := h.svc.GetExport(c.Request().Context(), id, user.ID, user.Role)
141		if err != nil {
142			return HandleDomainError(c, err)
143		}
144	
145		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: toExportResponse(job)})
146	}
147	
148	// DownloadExport handles GET /exports/:id/download.
149	func (h *ReportHandler) DownloadExport(c echo.Context) error {
150		user, ok := security.GetUserFromContext(c)
151		if !ok {
152			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
153		}
154	
155		id, err := uuid.Parse(c.Param("id"))
156		if err != nil {
157			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid export id"))
158		}
159	
160		// Service enforces creator-or-admin access.
161		job, err := h.svc.DownloadExport(c.Request().Context(), id, user.ID, user.Role)
162		if err != nil {
163			return HandleDomainError(c, err)
164		}
165	
166		if job.FilePath == "" {
167			return c.JSON(http.StatusNotFound, NewErrorResponse("NOT_FOUND", "export file not found"))
168		}
169	
170		filename := job.Filename
171		if filename == "" {
172			filename = filepath.Base(job.FilePath)
173		}
174		contentDisposition := mime.FormatMediaType("attachment", map[string]string{"filename": filename})
175		if contentDisposition != "" {
176			c.Response().Header().Set("Content-Disposition", contentDisposition)
177		}
178		if contentType := mime.TypeByExtension(filepath.Ext(filename)); contentType != "" {
179			c.Response().Header().Set("Content-Type", contentType)
180		} else {
181			c.Response().Header().Set("Content-Type", "application/octet-stream")
182		}
183		c.Response().Header().Set("Cache-Control", "no-store")
184	
185		return c.File(job.FilePath)
186	}
