188	// --- Private helpers ---
189	
190	func toReportResponse(r *domain.ReportDefinition) dto.ReportResponse {
191		roles := make([]string, len(r.AllowedRoles))
192		for i, role := range r.AllowedRoles {
193			roles[i] = string(role)
194		}
195		return dto.ReportResponse{
196			ID:           r.ID.String(),
197			Name:         r.Name,
198			ReportType:   r.ReportType,
199			Description:  r.Description,
200			AllowedRoles: roles,
201			CreatedAt:    r.CreatedAt.UTC().Format("2006-01-02T15:04:05Z07:00"),
202		}
203	}
204	
205	func toExportResponse(j *domain.ExportJob) dto.ExportResponse {
206		resp := dto.ExportResponse{
207			ID:        j.ID.String(),
208			ReportID:  j.ReportID.String(),
209			Format:    string(j.Format),
210			Filename:  j.Filename,
211			Status:    string(j.Status),
212			CreatedBy: j.CreatedBy.String(),
213			CreatedAt: j.CreatedAt.UTC().Format("2006-01-02T15:04:05Z07:00"),
214		}
215		if j.CompletedAt != nil {
216			s := j.CompletedAt.UTC().Format("2006-01-02T15:04:05Z07:00")
217			resp.CompletedAt = &s
218		}
219		return resp
220	}
