22	// ReportServiceImpl implements ReportService.
23	type ReportServiceImpl struct {
24		reportRepo  store.ReportRepository
25		exportRepo  store.ExportRepository
26		cfg         platform.Config
27		auditSvc    AuditService
28		pool        *pgxpool.Pool
29		queryDataFn func(ctx context.Context, reportType string, filters map[string]string) ([]map[string]interface{}, error)
30	}
31	
32	// WithQueryDataFn sets an override for queryReportData used in unit tests to
33	// inject failures without requiring a real database connection. Production code
34	// must never call this.
35	func (s *ReportServiceImpl) WithQueryDataFn(fn func(ctx context.Context, reportType string, filters map[string]string) ([]map[string]interface{}, error)) {
36		s.queryDataFn = fn
37	}
