39	// NewReportService creates a ReportServiceImpl backed by the given repositories.
40	func NewReportService(
41		reportRepo store.ReportRepository,
42		exportRepo store.ExportRepository,
43		cfg platform.Config,
44		auditSvc AuditService,
45		pool *pgxpool.Pool,
46	) *ReportServiceImpl {
47		return &ReportServiceImpl{
48			reportRepo: reportRepo,
49			exportRepo: exportRepo,
50			cfg:        cfg,
51			auditSvc:   auditSvc,
52			pool:       pool,
53		}
54	}
