56	// List returns the report definitions accessible to the given user role.
57	func (s *ReportServiceImpl) List(ctx context.Context, userRole domain.UserRole) ([]domain.ReportDefinition, error) {
58		reports, err := s.reportRepo.List(ctx)
59		if err != nil {
60			return nil, err
61		}
62	
63		filtered := make([]domain.ReportDefinition, 0, len(reports))
64		for _, r := range reports {
65			for _, allowed := range r.AllowedRoles {
66				if allowed == userRole {
67					filtered = append(filtered, r)
68					break
69				}
70			}
71		}
72	
73		return filtered, nil
74	}
75	
76	// GetReport retrieves a report definition by ID.
77	func (s *ReportServiceImpl) GetReport(ctx context.Context, id uuid.UUID) (*domain.ReportDefinition, error) {
78		return s.reportRepo.GetByID(ctx, id)
79	}
80	
81	// GetData returns a structured dataset for the given report.
82	// callerRole is checked against the report's AllowedRoles as a second authorization layer.
83	func (s *ReportServiceImpl) GetData(ctx context.Context, reportID uuid.UUID, filters map[string]string, callerRole domain.UserRole) (interface{}, error) {
84		report, err := s.reportRepo.GetByID(ctx, reportID)
85		if err != nil {
86			return nil, err
87		}
88	
89		allowed := false
90		for _, r := range report.AllowedRoles {
91			if r == callerRole {
92				allowed = true
93				break
94			}
95		}
96		if !allowed {
97			return nil, domain.ErrForbidden
98		}
99	
100		records, err := s.queryReportData(ctx, report.ReportType, filters)
101		if err != nil {
