112	// queryReportData dispatches to the appropriate SQL query for each report type.
113	func (s *ReportServiceImpl) queryReportData(ctx context.Context, reportType string, filters map[string]string) ([]map[string]interface{}, error) {
114		if s.queryDataFn != nil {
115			return s.queryDataFn(ctx, reportType, filters)
116		}
117		if filters == nil {
118			filters = map[string]string{}
119		}
120		switch reportType {
121		case "member_growth":
122			q, args := buildFilteredQuery(
123				`SELECT id::text, membership_status, joined_at FROM members`,
124				filters, map[string]string{"location_id": "location_id", "status": "membership_status", "_date": "joined_at"},
125				" ORDER BY joined_at DESC LIMIT 500")
126			return s.queryRows(ctx, q, args...)
127		case "churn":
128			q, args := buildFilteredQuery(
129				`SELECT id::text, membership_status, updated_at FROM members WHERE membership_status IN ('expired','cancelled')`,
130				filters, map[string]string{"location_id": "location_id", "_date": "updated_at"},
131				" ORDER BY updated_at DESC LIMIT 500")
132			return s.queryRows(ctx, q, args...)
133		case "renewal_rate":
134			q, args := buildFilteredQuery(
135				`SELECT membership_status, COUNT(*)::int AS count FROM members`,
136				filters, map[string]string{"location_id": "location_id"},
137				" GROUP BY membership_status")
138			return s.queryRows(ctx, q, args...)
139		case "engagement":
140			q, args := buildFilteredQuery(
141				`SELECT id::text, status, quantity, total_amount, created_at FROM orders`,
142				filters, map[string]string{"status": "status", "_date": "created_at"},
143				" ORDER BY created_at DESC LIMIT 500")
144			return s.queryRows(ctx, q, args...)
145		case "class_fill_rate":
146			q, args := buildFilteredQuery(
147				`SELECT id::text, status, min_quantity, current_committed_qty, cutoff_time FROM group_buy_campaigns`,
148				filters, map[string]string{"status": "status", "_date": "cutoff_time"},
149				" ORDER BY cutoff_time DESC LIMIT 500")
150			return s.queryRows(ctx, q, args...)
151		case "coach_productivity":
152			q, args := buildFilteredQuery(
153				`SELECT c.id::text, c.specialization, c.is_active,
154				        COUNT(m.id)::int AS member_count
155				 FROM coaches c
156				 LEFT JOIN members m ON m.location_id = c.location_id`,
157				filters, map[string]string{"location_id": "c.location_id", "coach_id": "c.id"},
158				" GROUP BY c.id, c.specialization, c.is_active")
159			return s.queryRows(ctx, q, args...)
160		case "inventory_summary":
161			q, args := buildFilteredQuery(
162				`SELECT id::text, name, category, quantity, status, unit_price FROM items`,
163				filters, map[string]string{"category": "category", "status": "status"},
164				" ORDER BY name LIMIT 500")
165			return s.queryRows(ctx, q, args...)
166		case "procurement_summary":
167			q, args := buildFilteredQuery(
168				`SELECT id::text, status, total_amount, created_at FROM purchase_orders`,
169				filters, map[string]string{"status": "status", "_date": "created_at"},
170				" ORDER BY created_at DESC LIMIT 500")
171			return s.queryRows(ctx, q, args...)
172		case "landed_cost_report":
173			q, args := buildFilteredQuery(
174				`SELECT item_id::text, purchase_order_id::text, period,
175				        cost_component, raw_amount, allocated_amount, allocation_method
176				 FROM landed_cost_entries`,
177				filters, map[string]string{"item_id": "item_id", "purchase_order_id": "purchase_order_id", "period": "period", "_date": "created_at"},
178				" ORDER BY created_at DESC LIMIT 500")
179			return s.queryRows(ctx, q, args...)
180		default:
181			return []map[string]interface{}{}, nil
182		}
183	}
