381	// GetExport retrieves an export job by ID. Access is granted to the creator
382	// or to roles with administrative report access (administrator, operations_manager).
383	func (s *ReportServiceImpl) GetExport(ctx context.Context, id uuid.UUID, callerID uuid.UUID, callerRole domain.UserRole) (*domain.ExportJob, error) {
384		job, err := s.exportRepo.GetByID(ctx, id)
385		if err != nil {
386			return nil, err
387		}
388		isOwner := job.CreatedBy == callerID
389		isAdmin := callerRole == domain.UserRoleAdministrator || callerRole == domain.UserRoleOperationsManager
390		if !isOwner && !isAdmin {
391			return nil, domain.ErrForbidden
392		}
393		return job, nil
394	}
