396	// DownloadExport returns the file path for a completed export job. Access is
397	// granted to the creator or to roles with administrative report access.
398	func (s *ReportServiceImpl) DownloadExport(ctx context.Context, id uuid.UUID, callerID uuid.UUID, callerRole domain.UserRole) (*domain.ExportJob, error) {
399		job, err := s.exportRepo.GetByID(ctx, id)
400		if err != nil {
401			return nil, err
402		}
403		isOwner := job.CreatedBy == callerID
404		isAdmin := callerRole == domain.UserRoleAdministrator || callerRole == domain.UserRoleOperationsManager
405		if !isOwner && !isAdmin {
406			return nil, domain.ErrForbidden
407		}
408		if job.Status != domain.ExportStatusCompleted {
409			return nil, &domain.ErrConflict{Entity: "export", Message: "export is not ready for download"}
410		}
411		if job.FilePath == "" {
412			return nil, domain.ErrNotFound
413		}
414		if _, err := os.Stat(job.FilePath); err != nil {
415			if os.IsNotExist(err) {
416				return nil, domain.ErrNotFound
417			}
418			return nil, fmt.Errorf("report.DownloadExport stat: %w", err)
419		}
420		return job, nil
421	}
