423	// recordsToRows converts report row maps to a tabular [][]string suitable for
424	// CSV/PDF export. The first row is a sorted header; subsequent rows are values.
425	// Falls back to a minimal metadata row when the records slice is empty.
426	func recordsToRows(reportType string, records []map[string]interface{}) [][]string {
427		if len(records) == 0 {
428			return [][]string{
429				{"report_type", "generated_at"},
430				{reportType, time.Now().UTC().Format(time.RFC3339)},
431			}
432		}
433		headers := make([]string, 0, len(records[0]))
434		for k := range records[0] {
435			headers = append(headers, k)
436		}
437		sort.Strings(headers)
438	
439		table := make([][]string, 0, len(records)+1)
440		table = append(table, headers)
441		for _, rec := range records {
442			row := make([]string, len(headers))
443			for i, h := range headers {
444				if v := rec[h]; v != nil {
445					row[i] = fmt.Sprintf("%v", v)
446				}
447			}
448			table = append(table, row)
449		}
450		return table
451	}
452	
453	// maskExportRecords applies role-based field masking to export records.
454	// Administrators and OperationsManagers see all data unmasked.
455	// All other roles have email addresses masked and phone/contact fields redacted.
456	func maskExportRecords(records []map[string]interface{}, role domain.UserRole) []map[string]interface{} {
457		if role == domain.UserRoleAdministrator || role == domain.UserRoleOperationsManager {
458			return records
459		}
460		masked := make([]map[string]interface{}, len(records))
461		for i, rec := range records {
462			m := make(map[string]interface{}, len(rec))
463			for k, v := range rec {
464				switch k {
465				case "email", "contact_email", "user_email":
466					if s, ok := v.(string); ok {
467						m[k] = maskExportEmail(s)
468					} else {
469						m[k] = v
470					}
471				case "phone", "contact_phone":
472					m[k] = "[REDACTED]"
473				default:
474					m[k] = v
475				}
476			}
477			masked[i] = m
478		}
479		return masked
480	}
481	
482	// maskExportEmail masks an email address, revealing only the first character and domain.
483	func maskExportEmail(email string) string {
484		idx := strings.Index(email, "@")
485		if idx <= 0 {
486			return "***@***"
487		}
488		return string(email[0]) + "***" + email[idx:]
489	}
490	
491	// writeCSV writes the given records as a CSV file at path.
492	func writeCSV(path string, records [][]string) error {
493		f, err := os.Create(path)
494		if err != nil {
495			return err
496		}
497		defer f.Close()
498	
499		w := csv.NewWriter(f)
500		if err := w.WriteAll(records); err != nil {
501			return err
502		}
503		w.Flush()
504		return w.Error()
505	}
506	
507	// writePDF writes the given records as a simple PDF file at path using gofpdf.
508	func writePDF(path string, title string, records [][]string) error {
509		pdf := gofpdf.New("P", "mm", "A4", "")
510		pdf.AddPage()
511		pdf.SetFont("Arial", "B", 14)
512		pdf.Cell(0, 10, title)
513		pdf.Ln(12)
514		pdf.SetFont("Arial", "", 10)
515		for _, row := range records {
516			for _, cell := range row {
517				pdf.Cell(60, 8, cell)
518			}
519			pdf.Ln(8)
520		}
521		return pdf.OutputFileAndClose(path)
522	}
