199	        id: varianceId,
200	        action,
201	        resolution_notes: notes.trim(),
202	        quantity_change: action === 'adjustment' ? Number(quantityChange) : undefined,
203	      });
204	      notify.success('Variance resolved.');
205	      setAction('adjustment');
206	      setNotes('');
207	      setQuantityChange('');
208	      onClose();
209	    } catch {
210	      notify.error('Failed to resolve variance.');
211	    }
212	  };
213	
214	  return (
215	    <Dialog open={open} onClose={onClose} maxWidth="xs" fullWidth>
