197	function SplitDialog({
198	  open,
199	  onClose,
200	  order,
201	  isOffline,
202	}: {
203	  open: boolean;
204	  onClose: () => void;
205	  order: Order;
206	  isOffline: boolean;
207	}) {
208	  const notify = useNotify();
209	  const splitMutation = useSplitOrder();
210	  const [quantitiesText, setQuantitiesText] = useState("");
211	
212	  useEffect(() => {
213	    if (!open) return;
214	    if (order.quantity > 1) {
215	      setQuantitiesText(`1,${order.quantity - 1}`);
216	      return;
217	    }
218	    setQuantitiesText(String(order.quantity));
219	  }, [open, order.quantity]);
220	
221	  const quantities = useMemo(
222	    () => parseSplitQuantities(quantitiesText),
223	    [quantitiesText],
224	  );
225	  const hasAtLeastTwo = quantities.length >= 2;
226	  const allPositive = quantities.every((quantity) => quantity > 0);
227	  const total = quantities.reduce((sum, quantity) => sum + quantity, 0);
228	  const isValid = hasAtLeastTwo && allPositive && total === order.quantity;
229	
230	  let helperText = `Enter at least 2 positive integers. Sum must equal ${order.quantity}.`;
231	  if (quantitiesText.trim()) {
232	    if (!hasAtLeastTwo) {
233	      helperText = "Provide at least 2 quantities.";
234	    } else if (!allPositive) {
235	      helperText = "Quantities must be positive integers.";
236	    } else if (total !== order.quantity) {
237	      helperText = `Current total is ${total}; expected ${order.quantity}.`;
238	    }
239	  }
240	
241	  const handleSubmit = async () => {
242	    if (!isValid) return;
243	    try {
244	      await splitMutation.mutateAsync({ id: order.id, quantities });
245	      notify.success("Order split successfully.");
246	      onClose();
247	    } catch {
248	      notify.error("Failed to split order.");
249	    }
250	  };
251	
252	  return (
253	    <Dialog open={open} onClose={onClose} maxWidth="xs" fullWidth>
254	      <DialogTitle>Split Order</DialogTitle>
255	      <DialogContent>
256	        {isOffline && (
257	          <Alert severity="warning" sx={{ mt: 1, mb: 2 }}>
258	            {OFFLINE_MUTATION_MESSAGE}
259	          </Alert>
260	        )}
261	        <Typography variant="body2" color="text.secondary" sx={{ mt: 1 }}>
262	          Original quantity: {order.quantity}
263	        </Typography>
264	        <TextField
265	          autoFocus
266	          margin="dense"
267	          label="Split Quantities"
268	          placeholder="e.g. 1,2,3"
269	          value={quantitiesText}
270	          onChange={(e) => setQuantitiesText(e.target.value)}
271	          fullWidth
272	          size="small"
273	          error={Boolean(quantitiesText.trim()) && !isValid}
274	          helperText={helperText}
275	        />
276	      </DialogContent>
277	      <DialogActions sx={{ px: 3, pb: 2 }}>
278	        <Button onClick={onClose} disabled={splitMutation.isPending}>
279	          Cancel
280	        </Button>
281	        <Button
282	          variant="contained"
283	          onClick={handleSubmit}
284	          disabled={splitMutation.isPending || !isValid || isOffline}
285	          startIcon={
286	            splitMutation.isPending ? (
287	              <CircularProgress size={16} color="inherit" />
288	            ) : undefined
289	          }
290	        >
291	          Split
292	        </Button>
293	      </DialogActions>
294	    </Dialog>
295	  );
296	}
