63	function CreateCampaignDialog({
64	  open,
65	  onClose,
66	  defaultItemID,
67	  itemReadOnly = false,
68	  title = 'Create Campaign',
69	  submitLabel = 'Create',
70	  isOffline = false,
71	}: {
72	  open: boolean;
73	  onClose: () => void;
74	  defaultItemID?: string;
75	  itemReadOnly?: boolean;
76	  title?: string;
77	  submitLabel?: string;
78	  isOffline?: boolean;
79	}) {
80	  const notify = useNotify();
81	  const createMutation = useCreateCampaign();
82	
83	  const {
84	    register,
85	    handleSubmit,
86	    reset,
87	    setValue,
88	    formState: { errors, isSubmitting },
89	  } = useForm<CreateCampaignFormData>({
90	    resolver: zodResolver(createCampaignSchema),
91	  });
92	
93	  useEffect(() => {
94	    if (!open) {
95	      return;
96	    }
97	    setValue('item_id', defaultItemID ?? '', {
98	      shouldDirty: false,
99	      shouldTouch: false,
100	      shouldValidate: false,
101	    });
102	  }, [open, defaultItemID, setValue]);
103	
104	  const onSubmit = async (data: CreateCampaignFormData) => {
105	    try {
106	      await createMutation.mutateAsync({
107	        item_id: data.item_id,
108	        min_quantity: data.min_quantity,
109	        cutoff_time: data.cutoff_time,
110	      });
111	      notify.success(submitLabel === 'Start' ? 'Group buy started successfully.' : 'Campaign created successfully.');
112	      reset();
113	      onClose();
114	    } catch {
115	      notify.error(submitLabel === 'Start' ? 'Failed to start group buy.' : 'Failed to create campaign.');
116	    }
117	  };
118	
119	  const handleClose = () => {
120	    reset();
121	    onClose();
122	  };
123	
124	  const itemIDHelperText = errors.item_id?.message
125	    ?? (itemReadOnly ? 'This campaign is locked to the selected catalog item.' : undefined);
126	
127	  return (
128	    <Dialog open={open} onClose={handleClose} maxWidth="sm" fullWidth>
129	      <DialogTitle>{title}</DialogTitle>
130	      <Box component="form" onSubmit={handleSubmit(onSubmit)} noValidate>
131	        <DialogContent sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
132	          {isOffline && (
133	            <Alert severity="warning">{OFFLINE_MUTATION_MESSAGE}</Alert>
134	          )}
135	          <TextField
136	            {...register('item_id')}
137	            label="Item ID (UUID)"
138	            fullWidth
139	            size="small"
140	            required
141	            disabled={itemReadOnly}
142	            error={Boolean(errors.item_id)}
143	            helperText={itemIDHelperText}
144	          />
145	          <TextField
146	            {...register('min_quantity', { valueAsNumber: true })}
147	            label="Minimum Quantity"
148	            fullWidth
149	            size="small"
150	            type="number"
151	            required
152	            inputProps={{ min: 1, step: 1 }}
153	            error={Boolean(errors.min_quantity)}
154	            helperText={errors.min_quantity?.message}
155	          />
156	          <TextField
157	            {...register('cutoff_time')}
158	            label="Cutoff Time"
159	            fullWidth
160	            size="small"
161	            type="datetime-local"
162	            required
163	            InputLabelProps={{ shrink: true }}
164	            error={Boolean(errors.cutoff_time)}
165	            helperText={errors.cutoff_time?.message}
166	          />
167	        </DialogContent>
168	        <DialogActions sx={{ px: 3, pb: 2 }}>
169	          <Button onClick={handleClose} disabled={isSubmitting}>Cancel</Button>
170	          <Button
171	            type="submit"
172	            variant="contained"
173	            disabled={isSubmitting || isOffline}
174	            startIcon={isSubmitting ? <CircularProgress size={16} color="inherit" /> : undefined}
175	          >
176	            {submitLabel}
177	          </Button>
178	        </DialogActions>
179	      </Box>
180	    </Dialog>
181	  );
182	}
