184	export default function GroupBuysPage() {
185	  const { user } = useAuth();
186	  const { isOffline } = useOfflineStatus();
187	  const navigate = useNavigate();
188	  const [searchParams, setSearchParams] = useSearchParams();
189	  const [page, setPage] = useState(0);
