193	
194	  const defaultItemID = searchParams.get('item_id') ?? undefined;
195	  const canCreateCampaign = user?.role === 'administrator' || user?.role === 'operations_manager';
196	  const memberStartingFromItem = user?.role === 'member' && Boolean(defaultItemID);
197	
198	  useEffect(() => {
199	    if (defaultItemID) {
200	      setCreateOpen(true);
201	    }
202	  }, [defaultItemID]);
203	
204	  const { data, isLoading, error, dataUpdatedAt } = useCampaignList({
205	    page: page + 1,
206	    page_size: pageSize,
207	    status: filters.status || undefined,
208	  });
209	  const emptyDescription = user?.role === 'member'
210	    ? 'Open a published catalog item to start a group buy, or join an existing campaign once it appears here.'
211	    : 'Create a group buy campaign to get started.';
212	
213	  const handleFiltersChange = useCallback((values: Record<string, string>) => {
214	    setFilters(values);
215	    setPage(0);
216	  }, []);
217	
218	  const handleCreateDialogClose = useCallback(() => {
219	    setCreateOpen(false);
