223	      setSearchParams(next, { replace: true });
224	    }
225	  }, [searchParams, setSearchParams]);
226	
227	  const columns: Column<GroupBuyCampaign>[] = [
228	    {
229	      key: 'item_id',
230	      label: 'Item',
231	      width: '28%',
232	      render: row => (
