234	          variant="body2"
235	          component="span"
236	          sx={{ cursor: 'pointer', fontWeight: 600, '&:hover': { textDecoration: 'underline' } }}
237	          onClick={() => navigate(`/group-buys/${row.id}`)}
238	        >
239	          {`Item ${row.item_id.slice(0, 8)}`}
240	        </Typography>
241	      ),
242	    },
243	    {
244	      key: 'status',
245	      label: 'Status',
246	      render: row => <StatusChip status={row.status} />,
247	    },
248	    {
249	      key: 'progress',
250	      label: 'Progress',
251	      width: '180px',
252	      render: row => <ProgressCell campaign={row} />,
253	    },
254	    {
255	      key: 'cutoff_time',
256	      label: 'Cutoff',
257	      render: row => new Date(row.cutoff_time).toLocaleString(),
258	    },
259	  ];
260	
261	  const rows = data?.data ?? [];
262	  const totalCount = data?.pagination.total_count ?? 0;
263	
264	  return (
265	    <PageContainer
266	      title="Group Buy Campaigns"
267	      breadcrumbs={[{ label: 'Group Buys' }]}
268	      actions={
269	        canCreateCampaign ? (
270	          <Button
271	            variant="contained"
272	            size="small"
273	            startIcon={<AddIcon />}
274	            onClick={() => setCreateOpen(true)}
275	            disabled={isOffline}
276	          >
277	            Create Campaign
278	          </Button>
279	        ) : null
280	      }
281	    >
282	      <Box sx={{ mb: 2 }}>
283	        <FilterBar fields={FILTER_FIELDS} onChange={handleFiltersChange} />
284	      </Box>
285	
286	      <OfflineDataNotice hasData={rows.length > 0} dataUpdatedAt={dataUpdatedAt} />
287	
288	      <DataTable
289	        columns={columns}
290	        rows={rows}
291	        rowKey={row => row.id}
292	        loading={isLoading}
293	        error={error ? 'Failed to load campaigns.' : null}
294	        page={page}
295	        pageSize={pageSize}
296	        totalCount={totalCount}
297	        onPageChange={setPage}
298	        onPageSizeChange={ps => { setPageSize(ps); setPage(0); }}
299	        emptyTitle="No campaigns found"
300	        emptyDescription={emptyDescription}
301	      />
302	
303	      <CreateCampaignDialog
304	        open={createOpen}
305	        onClose={handleCreateDialogClose}
306	        defaultItemID={defaultItemID}
307	        itemReadOnly={memberStartingFromItem}
308	        title={memberStartingFromItem ? 'Start Group Buy' : 'Create Campaign'}
309	        submitLabel={memberStartingFromItem ? 'Start' : 'Create'}
310	        isOffline={isOffline}
311	      />
312	    </PageContainer>
313	  );
314	}
