471	                          </Typography>
472	                        </TableCell>
473	                        <TableCell align="right">{line.ordered_quantity}</TableCell>
474	                        <TableCell align="right">${line.ordered_unit_price.toFixed(2)}</TableCell>
475	                        <TableCell align="right">{line.received_quantity ?? 0}</TableCell>
476	                        <TableCell align="right">
477	                          {line.received_unit_price != null ? `$${line.received_unit_price.toFixed(2)}` : '—'}
478	                        </TableCell>
479	                      </TableRow>
480	                    ))
481	                  )}
482	                </TableBody>
483	              </Table>
484	            </TableContainer>
485	          </Paper>
486	        </Grid>
487	
488	        {/* Variances Section */}
489	        <Grid item xs={12}>
490	          <Paper variant="outlined">
491	            <Box sx={{ px: 2, py: 1.5, borderBottom: 1, borderColor: 'divider' }}>
492	              <Typography variant="subtitle1" fontWeight={600}>Variances</Typography>
493	            </Box>
494	            <TableContainer>
495	              <Table size="small">
496	                <TableHead>
497	                  <TableRow>
498	                    <TableCell>Type</TableCell>
499	                    <TableCell align="right">Expected</TableCell>
500	                    <TableCell align="right">Actual</TableCell>
501	                    <TableCell>Status</TableCell>
502	                    <TableCell>Overdue</TableCell>
503	                    <TableCell />
504	                  </TableRow>
505	                </TableHead>
506	                <TableBody>
507	                  {variances.length === 0 ? (
508	                    <TableRow>
509	                      <TableCell colSpan={6}>
510	                        <Typography variant="body2" color="text.secondary" sx={{ py: 1 }}>
511	                          No variances recorded.
512	                        </Typography>
513	                      </TableCell>
514	                    </TableRow>
515	                  ) : (
516	                    variances.map(v => (
517	                      <TableRow key={v.id} hover>
518	                        <TableCell>{v.type}</TableCell>
519	                        <TableCell align="right">{v.expected_value}</TableCell>
520	                        <TableCell align="right">{v.actual_value}</TableCell>
521	                        <TableCell>
522	                          <StatusChip status={v.status} />
523	                        </TableCell>
524	                        <TableCell>
