13	// BackupJob runs database backups on a 24-hour interval.
14	type BackupJob struct {
15		svc      application.BackupService
16		logger   *slog.Logger
17		interval time.Duration
18	}
19	
20	func NewBackupJob(svc application.BackupService, logger *slog.Logger) *BackupJob {
21		return &BackupJob{svc: svc, logger: logger, interval: 24 * time.Hour}
22	}
23	
24	func NewBackupJobWithInterval(svc application.BackupService, logger *slog.Logger, interval time.Duration) *BackupJob {
25		return &BackupJob{svc: svc, logger: logger, interval: interval}
26	}
27	
28	func (j *BackupJob) Run(ctx context.Context) {
29		ticker := time.NewTicker(j.interval)
30		defer ticker.Stop()
31		for {
32			select {
33			case <-ctx.Done():
34				return
35			case <-ticker.C:
36				run, err := j.svc.Trigger(ctx, nil) // nil = system actor
37				if err != nil {
38					j.logger.Error("backup job error", "error", err)
39					continue
40				}
41				j.logger.Info("backup completed", "run_id", run.ID, "status", string(run.Status))
42			}
43		}
44	}
