55	}
56	
57	func NewVarianceDeadlineJobWithInterval(svc application.VarianceService, logger *slog.Logger, interval time.Duration) *VarianceDeadlineJob {
58		return &VarianceDeadlineJob{svc: svc, logger: logger, interval: interval}
59	}
60	
61	func (j *VarianceDeadlineJob) Run(ctx context.Context) {
62		ticker := time.NewTicker(j.interval)
63		defer ticker.Stop()
64		for {
65			select {
66			case <-ctx.Done():
67				return
68			case <-ticker.C:
69				count, err := j.svc.EscalateOverdue(ctx)
70				if err != nil {
71					j.logger.Error("variance escalation error", "error", err)
72					continue
73				}
74				if count > 0 {
75					j.logger.Warn("escalated overdue variances", "count", count)
76				}
77			}
78		}
79	}
