114	// BiometricKeyRotationJob ensures biometric encryption keys are present and
115	// rotated on schedule when the biometric module is enabled.
116	type BiometricKeyRotationJob struct {
117		svc          application.BiometricService
118		logger       *slog.Logger
119		rotationDays int
120		interval     time.Duration
121	}
122	
123	func NewBiometricKeyRotationJob(svc application.BiometricService, logger *slog.Logger, rotationDays int) *BiometricKeyRotationJob {
124		return &BiometricKeyRotationJob{
125			svc:          svc,
126			logger:       logger,
127			rotationDays: rotationDays,
128			interval:     24 * time.Hour,
129		}
130	}
131	
132	func NewBiometricKeyRotationJobWithInterval(svc application.BiometricService, logger *slog.Logger, rotationDays int, interval time.Duration) *BiometricKeyRotationJob {
133		return &BiometricKeyRotationJob{
134			svc:          svc,
135			logger:       logger,
136			rotationDays: rotationDays,
137			interval:     interval,
138		}
139	}
140	
141	func (j *BiometricKeyRotationJob) Run(ctx context.Context) {
142		if err := j.ensureKeyState(ctx); err != nil {
143			j.logger.Error("biometric key rotation check failed", "error", err)
144		}
145	
146		ticker := time.NewTicker(j.interval)
147		defer ticker.Stop()
148		for {
149			select {
150			case <-ctx.Done():
151				return
152			case <-ticker.C:
153				if err := j.ensureKeyState(ctx); err != nil {
154					j.logger.Error("biometric key rotation check failed", "error", err)
155				}
156			}
157		}
158	}
159	
160	func (j *BiometricKeyRotationJob) ensureKeyState(ctx context.Context) error {
161		key, err := j.svc.GetActiveKey(ctx)
162		if errors.Is(err, domain.ErrNotFound) {
163			rotated, rotateErr := j.svc.RotateKey(ctx, domain.SystemActorID)
164			if rotateErr != nil {
165				return rotateErr
166			}
167			j.logger.Info("bootstrapped biometric encryption key", "key_id", rotated.ID)
168			return nil
169		}
170		if err != nil {
171			return err
172		}
173	
174		if key.NeedsRotation(j.rotationDays) || time.Now().UTC().After(key.ExpiresAt) {
175			rotated, rotateErr := j.svc.RotateKey(ctx, domain.SystemActorID)
176			if rotateErr != nil {
177				return rotateErr
178			}
179			j.logger.Info("rotated biometric encryption key", "key_id", rotated.ID)
180		}
181	
182		return nil
183	}
