239	      helperText = "Quantities must be positive integers.";
240	    } else if (total !== order.quantity) {
241	      helperText = `Current total is ${total}; expected ${order.quantity}.`;
242	    }
243	  }
244	
245	  const handleSubmit = async () => {
246	    if (!isValid) return;
247	    try {
248	      await splitMutation.mutateAsync({ id: order.id, quantities });
