151	func (s *DashboardServiceImpl) renewalRate(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
152		curActive, err := s.countMembersByStatus(ctx, locationID, coachID, "active")
153		if err != nil {
154			return KPIValue{}, err
155		}
156		curTotal, err := s.countMembers(ctx, locationID, coachID, nil, nil)
157		if err != nil {
158			return KPIValue{}, err
159		}
160	
161		var curRate float64
162		if curTotal > 0 {
163			curRate = float64(curActive) / float64(curTotal) * 100
164		}
165	
166		// For previous period, approximate with churned vs total (no historical snapshot).
167		prevChurned, err := s.countChurnedMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
168		if err != nil {
169			return KPIValue{}, err
170		}
171		var prevRate float64
172		if curTotal > 0 {
173			prevRate = (1 - float64(prevChurned)/float64(max(curTotal, 1))) * 100
174		}
175		return makeKPI(curRate, prevRate, period), nil
176	}
