248	func (s *DashboardServiceImpl) countMembers(ctx context.Context, locationID, coachID *uuid.UUID, start, end *time.Time) (int, error) {
249		q := `SELECT COUNT(*) FROM members WHERE 1=1`
250		args := []interface{}{}
251		n := 1
252		if locationID != nil {
253			q += fmt.Sprintf(" AND location_id = $%d", n)
254			args = append(args, *locationID)
255			n++
256		}
257		if coachID != nil {
258			q += fmt.Sprintf(" AND location_id = (SELECT location_id FROM coaches WHERE id = $%d)", n)
259			args = append(args, *coachID)
260			n++
261		}
262		if start != nil {
263			q += fmt.Sprintf(" AND joined_at >= $%d", n)
264			args = append(args, *start)
265			n++
266		}
267		if end != nil {
268			q += fmt.Sprintf(" AND joined_at < $%d", n)
269			args = append(args, *end)
270		}
271		var count int
272		if err := s.pool.QueryRow(ctx, q, args...).Scan(&count); err != nil {
273			return 0, err
274		}
275		return count, nil
276	}
