356	func (s *DashboardServiceImpl) countCampaignsByStatus(ctx context.Context, locationID, coachID *uuid.UUID, status string, start, end *time.Time) (int, error) {
357		q := `SELECT COUNT(*) FROM group_buy_campaigns gbc JOIN items i ON i.id = gbc.item_id WHERE 1=1`
358		args := []interface{}{}
359		n := 1
360		if status != "" {
361			q += fmt.Sprintf(" AND gbc.status = $%d", n)
362			args = append(args, status)
363			n++
364		}
365		if locationID != nil {
366			q += fmt.Sprintf(" AND i.location_id = $%d", n)
367			args = append(args, *locationID)
368			n++
369		}
370		if coachID != nil {
371			q += fmt.Sprintf(" AND i.location_id = (SELECT location_id FROM coaches WHERE id = $%d)", n)
372			args = append(args, *coachID)
373			n++
374		}
375		if start != nil {
376			q += fmt.Sprintf(" AND gbc.created_at >= $%d", n)
377			args = append(args, *start)
378			n++
379		}
380		if end != nil {
381			q += fmt.Sprintf(" AND gbc.created_at < $%d", n)
382			args = append(args, *end)
383		}
384		var count int
385		if err := s.pool.QueryRow(ctx, q, args...).Scan(&count); err != nil {
386			return 0, err
387		}
388		return count, nil
389	}
