392		q := `SELECT COUNT(*) FROM coaches WHERE is_active = true`
393		args := []interface{}{}
394		if locationID != nil {
395			q += ` AND location_id = $1`
396			args = append(args, *locationID)
397		}
398		var count int
399		if err := s.pool.QueryRow(ctx, q, args...).Scan(&count); err != nil {
400			return 0, err
401		}
402		return count, nil
403	}
