405	func makeKPI(value, previous float64, period string) KPIValue {
406		var changePct float64
407		if previous != 0 {
408			changePct = (value - previous) / previous * 100
409		}
410		return KPIValue{
411			Value:         value,
412			PreviousValue: previous,
413			ChangePercent: changePct,
414			Period:        period,
415		}
416	}
