22	// GetKPIs computes the six dashboard KPI metrics.
23	// locationID filters by location (nil = all). period determines the date range
24	// (daily/weekly/monthly/quarterly/yearly; default monthly). coachID filters
25	// member-related metrics by assigned coach (nil = all coaches). category
26	// filters engagement metrics by item category (empty = all). from/to override
27	// period bounds when both are provided (format: 2006-01-02).
28	func (s *DashboardServiceImpl) GetKPIs(ctx context.Context, locationID *uuid.UUID, period string, coachID *uuid.UUID, category string, from, to string) (*DashboardKPIs, error) {
29		now := time.Now().UTC()
30		curStart, curEnd, prevStart, prevEnd, periodLabel := computePeriodBounds(now, period, from, to)
31	
32		memberGrowth, err := s.memberGrowth(ctx, locationID, coachID, curStart, curEnd, prevStart, prevEnd, periodLabel)
33		if err != nil {
34			return nil, fmt.Errorf("dashboard.memberGrowth: %w", err)
35		}
36	
37		churn, err := s.churn(ctx, locationID, coachID, curStart, curEnd, prevStart, prevEnd, periodLabel)
38		if err != nil {
39			return nil, fmt.Errorf("dashboard.churn: %w", err)
40		}
41	
42		renewalRate, err := s.renewalRate(ctx, locationID, coachID, curStart, curEnd, prevStart, prevEnd, periodLabel)
43		if err != nil {
44			return nil, fmt.Errorf("dashboard.renewalRate: %w", err)
45		}
46	
47		engagement, err := s.engagement(ctx, locationID, coachID, category, curStart, curEnd, prevStart, prevEnd, periodLabel)
48		if err != nil {
49			return nil, fmt.Errorf("dashboard.engagement: %w", err)
50		}
51	
52		classFillRate, err := s.classFillRate(ctx, locationID, coachID, curStart, curEnd, prevStart, prevEnd, periodLabel)
53		if err != nil {
54			return nil, fmt.Errorf("dashboard.classFillRate: %w", err)
55		}
56	
57		coachProductivity, err := s.coachProductivity(ctx, locationID, periodLabel)
58		if err != nil {
59			return nil, fmt.Errorf("dashboard.coachProductivity: %w", err)
60		}
61	
62		return &DashboardKPIs{
63			MemberGrowth:      memberGrowth,
64			Churn:             churn,
65			RenewalRate:       renewalRate,
66			Engagement:        engagement,
67			ClassFillRate:     classFillRate,
68			CoachProductivity: coachProductivity,
69		}, nil
70	}
71	
72	// computePeriodBounds calculates current and previous period date ranges from the
73	// given period label. from/to override with a custom range when both are non-empty.
74	func computePeriodBounds(now time.Time, period, from, to string) (curStart, curEnd, prevStart, prevEnd time.Time, label string) {
75		if from != "" && to != "" {
76			curStart, _ = time.Parse("2006-01-02", from)
77			curEnd, _ = time.Parse("2006-01-02", to)
78			curStart = curStart.UTC()
79			curEnd = curEnd.UTC().Add(24*time.Hour - time.Nanosecond)
80			duration := curEnd.Sub(curStart)
81			prevStart = curStart.Add(-duration)
82			prevEnd = curStart
83			label = from + "/" + to
84			return
85		}
86		switch period {
87		case "daily":
88			curStart = time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, time.UTC)
89			curEnd = now
90			prevStart = curStart.AddDate(0, 0, -1)
91			prevEnd = curStart
92			label = curStart.Format("2006-01-02")
93		case "weekly":
94			weekday := int(now.Weekday())
95			if weekday == 0 {
96				weekday = 7
97			}
98			curStart = now.AddDate(0, 0, -(weekday - 1)).Truncate(24 * time.Hour)
99			curEnd = now
100			prevStart = curStart.AddDate(0, 0, -7)
101			prevEnd = curStart
102			_, week := curStart.ISOWeek()
103			label = fmt.Sprintf("%d-W%02d", curStart.Year(), week)
104		case "quarterly":
105			quarter := (int(now.Month()) - 1) / 3
106			curStart = time.Date(now.Year(), time.Month(quarter*3+1), 1, 0, 0, 0, 0, time.UTC)
107			curEnd = now
108			prevStart = curStart.AddDate(0, -3, 0)
109			prevEnd = curStart
110			label = fmt.Sprintf("%d-Q%d", now.Year(), quarter+1)
111		case "yearly":
112			curStart = time.Date(now.Year(), 1, 1, 0, 0, 0, 0, time.UTC)
113			curEnd = now
114			prevStart = curStart.AddDate(-1, 0, 0)
115			prevEnd = curStart
116			label = fmt.Sprintf("%d", now.Year())
117		default: // "monthly"
118			curStart = time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
119			curEnd = now
120			prevStart = curStart.AddDate(0, -1, 0)
121			prevEnd = curStart
122			label = curStart.Format("2006-01")
123		}
124		return
125	}
