178	func (s *DashboardServiceImpl) engagement(ctx context.Context, locationID, coachID *uuid.UUID, category string, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
179		curOrders, err := s.countOrders(ctx, locationID, coachID, category, curStart, curEnd)
180		if err != nil {
181			return KPIValue{}, err
182		}
183		curMembers, err := s.countMembers(ctx, locationID, coachID, nil, nil)
184		if err != nil {
185			return KPIValue{}, err
186		}
187		prevOrders, err := s.countOrders(ctx, locationID, coachID, category, prevStart, prevEnd)
188		if err != nil {
189			return KPIValue{}, err
190		}
191	
192		var curRate, prevRate float64
193		if curMembers > 0 {
194			curRate = float64(curOrders) / float64(curMembers)
195			prevRate = float64(prevOrders) / float64(curMembers)
196		}
197		return makeKPI(curRate, prevRate, period), nil
198	}
