171	func resetDatabase(t *testing.T, cfg platform.Config) {
172		t.Helper()
173	
174		db, err := sql.Open("pgx", cfg.DatabaseURL)
175		if err != nil {
176			t.Fatalf("open database: %v", err)
177		}
178		defer db.Close()
179		db.SetMaxOpenConns(1)
180		db.SetMaxIdleConns(1)
181	
182		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
183		defer cancel()
184	
185		if err := db.PingContext(ctx); err != nil {
186			t.Fatalf("ping database: %v", err)
187		}
188	
189		statements := []string{
190			`DROP SCHEMA IF EXISTS public CASCADE`,
191			`CREATE SCHEMA public`,
192			`CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA public`,
193		}
194		for _, stmt := range statements {
195			if _, err := db.ExecContext(ctx, stmt); err != nil {
196				t.Fatalf("exec %q: %v", stmt, err)
197			}
198		}
199	
200		if _, err := db.ExecContext(ctx, `SET search_path TO public`); err != nil {
201			t.Fatalf("set search_path: %v", err)
202		}
203	
204		gooseOnce.Do(func() {
205			if err := goose.SetDialect("postgres"); err != nil {
206				panic(err)
207			}
208		})
209	
210		if err := goose.UpContext(ctx, db, filepath.Join(backendRoot(t), "database", "migrations")); err != nil {
211			t.Fatalf("run migrations: %v", err)
212		}
213	
214		seedSQL, err := os.ReadFile(filepath.Join(backendRoot(t), "database", "seeds", "seed.sql"))
215		if err != nil {
216			t.Fatalf("read seed.sql: %v", err)
217		}
218		if _, err := db.ExecContext(ctx, string(seedSQL)); err != nil {
219			t.Fatalf("run seed.sql: %v", err)
220		}
221	}
