16	// BiometricHandler handles HTTP requests for biometric and encryption key endpoints.
17	type BiometricHandler struct {
18		svc application.BiometricService
19		cfg platform.Config
20	}
21	
22	// NewBiometricHandler creates a BiometricHandler backed by the given service and config.
23	func NewBiometricHandler(svc application.BiometricService, cfg platform.Config) *BiometricHandler {
24		return &BiometricHandler{svc: svc, cfg: cfg}
25	}
26	
27	// RegisterBiometric handles POST /admin/biometrics.
28	func (h *BiometricHandler) RegisterBiometric(c echo.Context) error {
29		if !h.cfg.BiometricModuleEnabled {
30			return c.JSON(http.StatusNotImplemented, NewErrorResponse("MODULE_DISABLED", "biometric module is not enabled"))
31		}
32	
33		var req dto.RegisterBiometricRequest
34		if err := c.Bind(&req); err != nil {
35			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid request body"))
36		}
37	
38		userID, err := uuid.Parse(req.UserID)
39		if err != nil {
40			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid user_id"))
41		}
42	
43		enrollment, err := h.svc.Register(c.Request().Context(), userID, req.TemplateRef)
44		if err != nil {
45			return HandleDomainError(c, err)
46		}
47	
48		return c.JSON(http.StatusCreated, dto.SuccessResponse{Data: toBiometricResponse(enrollment)})
49	}
50	
51	// GetBiometric handles GET /admin/biometrics/:user_id.
52	func (h *BiometricHandler) GetBiometric(c echo.Context) error {
53		if !h.cfg.BiometricModuleEnabled {
54			return c.JSON(http.StatusNotImplemented, NewErrorResponse("MODULE_DISABLED", "biometric module is not enabled"))
55		}
56	
57		userID, err := uuid.Parse(c.Param("user_id"))
58		if err != nil {
59			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid user_id"))
60		}
61	
62		enrollment, err := h.svc.GetByUser(c.Request().Context(), userID)
63		if err != nil {
64			return HandleDomainError(c, err)
65		}
66	
67		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: toBiometricResponse(enrollment)})
68	}
69	
70	// RevokeBiometric handles POST /admin/biometrics/:user_id/revoke.
71	func (h *BiometricHandler) RevokeBiometric(c echo.Context) error {
72		if !h.cfg.BiometricModuleEnabled {
73			return c.JSON(http.StatusNotImplemented, NewErrorResponse("MODULE_DISABLED", "biometric module is not enabled"))
74		}
75	
76		userID, err := uuid.Parse(c.Param("user_id"))
77		if err != nil {
78			return c.JSON(http.StatusBadRequest, NewErrorResponse("BAD_REQUEST", "invalid user_id"))
79		}
80	
81		if err := h.svc.Revoke(c.Request().Context(), userID); err != nil {
82			return HandleDomainError(c, err)
83		}
84	
85		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: map[string]string{"message": "biometric enrollment revoked"}})
86	}
87	
88	// RotateKey handles POST /admin/biometrics/rotate-key.
89	func (h *BiometricHandler) RotateKey(c echo.Context) error {
90		if !h.cfg.BiometricModuleEnabled {
91			return c.JSON(http.StatusNotImplemented, NewErrorResponse("MODULE_DISABLED", "biometric module is not enabled"))
92		}
93	
94		user, ok := security.GetUserFromContext(c)
95		if !ok {
96			return c.JSON(http.StatusUnauthorized, NewErrorResponse("UNAUTHORIZED", "not authenticated"))
97		}
98	
99		key, err := h.svc.RotateKey(c.Request().Context(), user.ID)
100		if err != nil {
101			return HandleDomainError(c, err)
102		}
103	
104		return c.JSON(http.StatusOK, dto.SuccessResponse{Data: toEncryptionKeyResponse(key)})
105	}
106	
107	// ListKeys handles GET /admin/biometrics/keys.
108	func (h *BiometricHandler) ListKeys(c echo.Context) error {
109		if !h.cfg.BiometricModuleEnabled {
110			return c.JSON(http.StatusNotImplemented, NewErrorResponse("MODULE_DISABLED", "biometric module is not enabled"))
111		}
112	
113		keys, err := h.svc.ListKeys(c.Request().Context())
114		if err != nil {
115			return HandleDomainError(c, err)
116		}
117	
118		resp := make([]dto.EncryptionKeyResponse, len(keys))
119		for i := range keys {
