67	// Register creates a new biometric enrollment for the given user. The
68	// templateRef is an opaque reference; raw biometric data never enters the
69	// application layer. The reference is encrypted with AES-256-GCM using the
70	// active biometric encryption key before storage.
71	func (s *BiometricServiceImpl) Register(ctx context.Context, userID uuid.UUID, templateRef string) (*domain.BiometricEnrollment, error) {
72		activeKey, err := s.ensureActiveKey(ctx)
73		if err != nil {
74			return nil, fmt.Errorf("biometric.Register: no active encryption key: %w", err)
75		}
76	
77		aesKey, err := s.unwrapDEK(activeKey)
78		if err != nil {
79			return nil, fmt.Errorf("biometric.Register: %w", err)
80		}
81	
82		encrypted, err := security.EncryptAESGCM([]byte(templateRef), aesKey)
83		if err != nil {
84			return nil, fmt.Errorf("biometric.Register: encryption failed: %w", err)
85		}
86	
87		now := time.Now().UTC()
88		enrollment := &domain.BiometricEnrollment{
89			ID:              uuid.New(),
90			UserID:          userID,
91			EncryptedData:   encrypted,
92			EncryptionKeyID: activeKey.ID,
93			CreatedAt:       now,
94			UpdatedAt:       now,
95		}
96	
97		if err := s.biometricRepo.Create(ctx, enrollment); err != nil {
98			return nil, err
99		}
100	
101		_ = s.auditSvc.Log(ctx, "biometric.registered", "biometric_enrollment", enrollment.ID, userID, map[string]interface{}{})
102	
103		return enrollment, nil
104	}
