106	// GetByUser retrieves the biometric enrollment for the given user, with the
107	// encrypted data replaced by a redaction placeholder so raw data is never
108	// exposed outside this layer.
109	func (s *BiometricServiceImpl) GetByUser(ctx context.Context, userID uuid.UUID) (*domain.BiometricEnrollment, error) {
110		enrollment, err := s.biometricRepo.GetByUserID(ctx, userID)
111		if err != nil {
112			return nil, err
113		}
114	
115		copy := *enrollment
116		copy.EncryptedData = []byte(security.RedactBiometric())
117		return &copy, nil
118	}
