120	// Revoke clears the biometric data for the given user's enrollment record.
121	func (s *BiometricServiceImpl) Revoke(ctx context.Context, userID uuid.UUID) error {
122		enrollment, err := s.biometricRepo.GetByUserID(ctx, userID)
123		if err != nil {
124			return err
125		}
126	
127		enrollment.EncryptedData = []byte{}
128		enrollment.UpdatedAt = time.Now().UTC()
129	
130		if err := s.biometricRepo.Update(ctx, enrollment); err != nil {
131			return err
132		}
133	
134		_ = s.auditSvc.Log(ctx, "biometric.revoked", "biometric_enrollment", enrollment.ID, userID, map[string]interface{}{})
135	
136		return nil
137	}
