139	// RotateKey rotates the active biometric envelope key and re-encrypts existing
140	// enrollment references under the new active key inside one transaction.
141	func (s *BiometricServiceImpl) RotateKey(ctx context.Context, performedBy uuid.UUID) (*domain.EncryptionKey, error) {
142		var newKey *domain.EncryptionKey
143	
144		err := withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
145			oldKey, err := s.encKeyRepo.GetActive(txCtx, "biometric")
146			if err != nil && err != domain.ErrNotFound {
147				return err
148			}
149	
150			// Generate a fresh random DEK for the new key slot.
151			newDEK, err := security.GenerateAESKey()
152			if err != nil {
153				return fmt.Errorf("biometric.RotateKey: DEK generation failed: %w", err)
154			}
155			kek, err := security.DeriveKeyFromRef(s.cfg.BiometricMasterKeyRef)
156			if err != nil {
157				return fmt.Errorf("biometric.RotateKey: KEK derivation failed: %w", err)
158			}
159			wrappedDEK, err := security.WrapDEK(newDEK, kek)
160			if err != nil {
161				return fmt.Errorf("biometric.RotateKey: DEK wrap failed: %w", err)
162			}
163	
164			newKey = &domain.EncryptionKey{
165				ID:           uuid.New(),
166				KeyReference: uuid.New().String(),
167				WrappedDEK:   wrappedDEK,
168				Purpose:      "biometric",
169				Status:       domain.EncryptionKeyStatusActive,
170				ActivatedAt:  time.Now().UTC(),
171				ExpiresAt:    time.Now().UTC().AddDate(0, 0, s.rotationDays),
172			}
173			newAESKey := newDEK
174	
175			var oldAESKey []byte
176			if oldKey != nil && err != domain.ErrNotFound {
177				oldAESKey, err = s.unwrapDEK(oldKey)
178				if err != nil {
179					return fmt.Errorf("biometric.RotateKey old key unwrap failed: %w", err)
180				}
181			}
182	
183			if err := s.encKeyRepo.Create(txCtx, newKey); err != nil {
184				return err
185			}
186	
187			enrollments, err := s.biometricRepo.List(txCtx)
188			if err != nil {
189				return err
190			}
191			for i := range enrollments {
192				if len(enrollments[i].EncryptedData) == 0 || oldAESKey == nil {
193					enrollments[i].EncryptionKeyID = newKey.ID
194					enrollments[i].UpdatedAt = time.Now().UTC()
195					if err := s.biometricRepo.Update(txCtx, &enrollments[i]); err != nil {
196						return err
197					}
198					continue
199				}
200	
201				plaintext, err := security.DecryptAESGCM(enrollments[i].EncryptedData, oldAESKey)
202				if err != nil {
203					return fmt.Errorf("biometric.RotateKey decrypt enrollment %s: %w", enrollments[i].ID, err)
204				}
205				reencrypted, err := security.EncryptAESGCM(plaintext, newAESKey)
206				if err != nil {
207					return fmt.Errorf("biometric.RotateKey re-encrypt enrollment %s: %w", enrollments[i].ID, err)
208				}
209	
210				enrollments[i].EncryptedData = reencrypted
211				enrollments[i].EncryptionKeyID = newKey.ID
212				enrollments[i].UpdatedAt = time.Now().UTC()
213				if err := s.biometricRepo.Update(txCtx, &enrollments[i]); err != nil {
214					return err
215				}
216			}
217	
218			if oldKey != nil && err != domain.ErrNotFound {
219				now := time.Now().UTC()
220				oldKey.Status = domain.EncryptionKeyStatusRotated
221				oldKey.RotatedAt = &now
222				if err := s.encKeyRepo.Update(txCtx, oldKey); err != nil {
223					return err
224				}
225			}
226	
227			return s.auditSvc.Log(txCtx, "encryption_key.rotated", "encryption_key", newKey.ID, performedBy, map[string]interface{}{
228				"re_encrypted_enrollments": len(enrollments),
229			})
230		})
231		if err != nil {
232			return nil, err
233		}
234	
235		return newKey, nil
236	}
