248	func (s *BiometricServiceImpl) ensureActiveKey(ctx context.Context) (*domain.EncryptionKey, error) {
249		activeKey, err := s.encKeyRepo.GetActive(ctx, "biometric")
250		if errors.Is(err, domain.ErrNotFound) || (err == nil && len(activeKey.WrappedDEK) == 0) {
251			// No active key, or the active key pre-dates envelope encryption (legacy row).
252			// Rotate to create a proper key with a wrapped DEK.
253			if _, rotateErr := s.RotateKey(ctx, domain.SystemActorID); rotateErr != nil {
254				return nil, rotateErr
255			}
256			return s.encKeyRepo.GetActive(ctx, "biometric")
257		}
258		if err != nil {
259			return nil, err
260		}
261		return activeKey, nil
