151	func (s *DashboardServiceImpl) renewalRate(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
152		curActive, err := s.countMembersByStatus(ctx, locationID, coachID, "active")
153		if err != nil {
154			return KPIValue{}, err
155		}
156		// Total members who had joined by the end of the current period.
157		curTotalAtEnd, err := s.countMembers(ctx, locationID, coachID, nil, &curEnd)
158		if err != nil {
159			return KPIValue{}, err
160		}
161	
162		var curRate float64
163		if curTotalAtEnd > 0 {
164			curRate = float64(curActive) / float64(curTotalAtEnd) * 100
165		}
166	
167		// Total members who had joined by the end of the previous period.
168		prevTotalAtEnd, err := s.countMembers(ctx, locationID, coachID, nil, &prevEnd)
169		if err != nil {
170			return KPIValue{}, err
171		}
172		prevChurned, err := s.countChurnedMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
173		if err != nil {
174			return KPIValue{}, err
175		}
176		var prevRate float64
177		if prevTotalAtEnd > 0 {
178			prevRate = float64(prevTotalAtEnd-prevChurned) / float64(prevTotalAtEnd) * 100
179		}
180		return makeKPI(curRate, prevRate, period), nil
181	}
