16	
17	// MemberStore implements store.MemberRepository using a pgx connection pool.
18	type MemberStore struct {
19		pool *pgxpool.Pool
20	}
21	
22	// NewMemberStore creates a new MemberStore backed by the given pool.
23	func NewMemberStore(pool *pgxpool.Pool) *MemberStore {
24		return &MemberStore{pool: pool}
25	}
26	
27	// Create inserts a new member record.
28	func (s *MemberStore) Create(ctx context.Context, member *domain.Member) error {
29		const q = `
30			INSERT INTO members (id, user_id, location_id, membership_status, joined_at, renewal_date, created_at, updated_at)
31			VALUES ($1,$2,$3,$4,$5,$6,$7,$8)`
32		_, err := s.pool.Exec(ctx, q,
33			member.ID, member.UserID, member.LocationID, member.MembershipStatus,
34			member.JoinedAt, member.RenewalDate, member.CreatedAt, member.UpdatedAt,
35		)
36		if err != nil {
37			return fmt.Errorf("member_store.Create: %w", err)
38		}
39		return nil
40	}
41	
42	// GetByID retrieves a member by UUID.
43	func (s *MemberStore) GetByID(ctx context.Context, id uuid.UUID) (*domain.Member, error) {
44		const q = `
45			SELECT id, user_id, location_id, membership_status, joined_at, renewal_date, created_at, updated_at
46			FROM members WHERE id = $1 LIMIT 1`
47		row := s.pool.QueryRow(ctx, q, id)
48		m, err := scanMember(row)
49		if err != nil {
50			if errors.Is(err, pgx.ErrNoRows) {
51				return nil, domain.ErrNotFound
52			}
53			return nil, fmt.Errorf("member_store.GetByID: %w", err)
54		}
55		return m, nil
56	}
57	
58	// GetByUserID retrieves the member record associated with a user.
59	func (s *MemberStore) GetByUserID(ctx context.Context, userID uuid.UUID) (*domain.Member, error) {
60		const q = `
61			SELECT id, user_id, location_id, membership_status, joined_at, renewal_date, created_at, updated_at
62			FROM members WHERE user_id = $1 LIMIT 1`
63		row := s.pool.QueryRow(ctx, q, userID)
64		m, err := scanMember(row)
65		if err != nil {
66			if errors.Is(err, pgx.ErrNoRows) {
67				return nil, domain.ErrNotFound
68			}
69			return nil, fmt.Errorf("member_store.GetByUserID: %w", err)
70		}
71		return m, nil
72	}
73	
74	// List returns a paginated list of members, optionally filtered by location.
75	func (s *MemberStore) List(ctx context.Context, locationID *uuid.UUID, page, pageSize int) ([]domain.Member, int, error) {
76		offset := (page - 1) * pageSize
77	
78		var (
79			total int
80			rows  pgx.Rows
81			err   error
82		)
83	
84		if locationID != nil {
85			if err = s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM members WHERE location_id = $1`, *locationID).Scan(&total); err != nil {
86				return nil, 0, fmt.Errorf("member_store.List count: %w", err)
87			}
88			rows, err = s.pool.Query(ctx, `
89				SELECT id, user_id, location_id, membership_status, joined_at, renewal_date, created_at, updated_at
90				FROM members WHERE location_id = $1 ORDER BY joined_at DESC LIMIT $2 OFFSET $3`,
91				*locationID, pageSize, offset)
92		} else {
93			if err = s.pool.QueryRow(ctx, `SELECT COUNT(*) FROM members`).Scan(&total); err != nil {
94				return nil, 0, fmt.Errorf("member_store.List count: %w", err)
95			}
96			rows, err = s.pool.Query(ctx, `
97				SELECT id, user_id, location_id, membership_status, joined_at, renewal_date, created_at, updated_at
98				FROM members ORDER BY joined_at DESC LIMIT $1 OFFSET $2`,
99				pageSize, offset)
100		}
101		if err != nil {
102			return nil, 0, fmt.Errorf("member_store.List: %w", err)
103		}
104		defer rows.Close()
105	
106		var members []domain.Member
107		for rows.Next() {
108			m, err := scanMember(rows)
109			if err != nil {
110				return nil, 0, fmt.Errorf("member_store.List scan: %w", err)
111			}
112			members = append(members, *m)
113		}
114		if err := rows.Err(); err != nil {
115			return nil, 0, fmt.Errorf("member_store.List rows: %w", err)
116		}
117		return members, total, nil
118	}
119	
120	// CountByPeriod returns the count of members who joined within the given time range.
121	func (s *MemberStore) CountByPeriod(ctx context.Context, locationID *uuid.UUID, start, end time.Time) (int, error) {
122		var count int
123		var err error
124		if locationID != nil {
125			err = s.pool.QueryRow(ctx,
126				`SELECT COUNT(*) FROM members WHERE location_id = $1 AND joined_at >= $2 AND joined_at < $3`,
127				*locationID, start, end).Scan(&count)
128		} else {
129			err = s.pool.QueryRow(ctx,
130				`SELECT COUNT(*) FROM members WHERE joined_at >= $1 AND joined_at < $2`,
131				start, end).Scan(&count)
132		}
133		if err != nil {
134			return 0, fmt.Errorf("member_store.CountByPeriod: %w", err)
135		}
136		return count, nil
137	}
138	
139	func scanMember(row pgx.Row) (*domain.Member, error) {
140		var m domain.Member
141		err := row.Scan(
142			&m.ID, &m.UserID, &m.LocationID, &m.MembershipStatus,
143			&m.JoinedAt, &m.RenewalDate, &m.CreatedAt, &m.UpdatedAt,
144		)
145		if err != nil {
146			return nil, err
147		}
148		return &m, nil
149	}
150	
151	// Compile-time interface assertion.
152	var _ store.MemberRepository = (*MemberStore)(nil)
