127	func (s *DashboardServiceImpl) memberGrowth(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
128		cur, err := s.countMembers(ctx, locationID, coachID, &curStart, &curEnd)
129		if err != nil {
130			return KPIValue{}, err
131		}
132		prev, err := s.countMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
133		if err != nil {
134			return KPIValue{}, err
135		}
136		return makeKPI(float64(cur), float64(prev), period), nil
137	}
138	
139	func (s *DashboardServiceImpl) churn(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
140		cur, err := s.countChurnedMembers(ctx, locationID, coachID, &curStart, &curEnd)
141		if err != nil {
142			return KPIValue{}, err
143		}
144		prev, err := s.countChurnedMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
145		if err != nil {
146			return KPIValue{}, err
147		}
148		return makeKPI(float64(cur), float64(prev), period), nil
149	}
150	
151	func (s *DashboardServiceImpl) renewalRate(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
152		curActive, err := s.countMembersByStatus(ctx, locationID, coachID, "active")
153		if err != nil {
154			return KPIValue{}, err
155		}
156		// Total members who had joined by the end of the current period.
157		curTotalAtEnd, err := s.countMembers(ctx, locationID, coachID, nil, &curEnd)
158		if err != nil {
159			return KPIValue{}, err
160		}
161	
162		var curRate float64
163		if curTotalAtEnd > 0 {
164			curRate = float64(curActive) / float64(curTotalAtEnd) * 100
165		}
166	
167		// Total members who had joined by the end of the previous period.
168		prevTotalAtEnd, err := s.countMembers(ctx, locationID, coachID, nil, &prevEnd)
169		if err != nil {
170			return KPIValue{}, err
171		}
172		prevChurned, err := s.countChurnedMembers(ctx, locationID, coachID, &prevStart, &prevEnd)
173		if err != nil {
174			return KPIValue{}, err
175		}
176		var prevRate float64
177		if prevTotalAtEnd > 0 {
178			prevRate = float64(prevTotalAtEnd-prevChurned) / float64(prevTotalAtEnd) * 100
179		}
180		return makeKPI(curRate, prevRate, period), nil
181	}
182	
183	func (s *DashboardServiceImpl) engagement(ctx context.Context, locationID, coachID *uuid.UUID, category string, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
184		curOrders, err := s.countOrders(ctx, locationID, coachID, category, curStart, curEnd)
185		if err != nil {
186			return KPIValue{}, err
187		}
188		curMembers, err := s.countMembers(ctx, locationID, coachID, nil, nil)
189		if err != nil {
190			return KPIValue{}, err
191		}
192		prevOrders, err := s.countOrders(ctx, locationID, coachID, category, prevStart, prevEnd)
193		if err != nil {
194			return KPIValue{}, err
195		}
196	
197		var curRate, prevRate float64
198		if curMembers > 0 {
199			curRate = float64(curOrders) / float64(curMembers)
200			prevRate = float64(prevOrders) / float64(curMembers)
201		}
202		return makeKPI(curRate, prevRate, period), nil
203	}
