205	func (s *DashboardServiceImpl) classFillRate(ctx context.Context, locationID, coachID *uuid.UUID, curStart, curEnd, prevStart, prevEnd time.Time, period string) (KPIValue, error) {
206		curRate, err := s.avgCampaignFillRate(ctx, locationID, coachID, &curStart, &curEnd)
207		if err != nil {
208			return KPIValue{}, err
