217	func (s *DashboardServiceImpl) coachProductivity(ctx context.Context, locationID, coachID *uuid.UUID, period string) (KPIValue, error) {
218		activeMembers, err := s.countMembersByStatus(ctx, locationID, coachID, "active")
219		if err != nil {
220			return KPIValue{}, err
221		}
222		activeCoaches, err := s.countActiveCoaches(ctx, locationID, coachID)
223		if err != nil {
224			return KPIValue{}, err
225		}
226	
227		var ratio float64
228		if activeCoaches > 0 {
229			ratio = float64(activeMembers) / float64(activeCoaches)
230		}
231		// No meaningful previous period comparison without historical snapshots.
232		return makeKPI(ratio, ratio, period), nil
233	}
