345	// avgCampaignFillRate returns the average fill percentage across campaigns in the
346	// given period: AVG(current_committed_qty / min_quantity * 100). min_quantity is
347	// guaranteed > 0 by the schema CHECK constraint so no division-by-zero guard is
348	// needed. Returns 0 when no campaigns exist in the period.
349	func (s *DashboardServiceImpl) avgCampaignFillRate(ctx context.Context, locationID, coachID *uuid.UUID, start, end *time.Time) (float64, error) {
350		q := `SELECT COALESCE(AVG(gbc.current_committed_qty::float / gbc.min_quantity * 100), 0)
351		      FROM group_buy_campaigns gbc
352		      JOIN items i ON i.id = gbc.item_id
353		      WHERE 1=1`
354		args := []interface{}{}
355		n := 1
356		if locationID != nil {
357			q += fmt.Sprintf(" AND i.location_id = $%d", n)
358			args = append(args, *locationID)
359			n++
360		}
361		if coachID != nil {
362			q += fmt.Sprintf(" AND i.location_id = (SELECT location_id FROM coaches WHERE id = $%d)", n)
363			args = append(args, *coachID)
364			n++
365		}
366		if start != nil {
367			q += fmt.Sprintf(" AND gbc.created_at >= $%d", n)
368			args = append(args, *start)
369			n++
370		}
371		if end != nil {
372			q += fmt.Sprintf(" AND gbc.created_at < $%d", n)
373			args = append(args, *end)
374		}
375		var rate float64
376		if err := s.pool.QueryRow(ctx, q, args...).Scan(&rate); err != nil {
377			return 0, err
378		}
379		return rate, nil
380	}
