402	func makeKPI(value, previous float64, period string) KPIValue {
403		var changePct float64
404		if previous != 0 {
405			changePct = (value - previous) / previous * 100
406		}
407		return KPIValue{
408			Value:         value,
409			PreviousValue: previous,
410			ChangePercent: changePct,
411			Period:        period,
412		}
413	}
