55	func (s *CampaignServiceImpl) Create(ctx context.Context, campaign *domain.GroupBuyCampaign) (*domain.GroupBuyCampaign, error) {
56		now := time.Now().UTC()
57		if err := withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
58			item, err := s.items.GetByID(txCtx, campaign.ItemID)
59			if err != nil {
60				return err
61			}
62			if item.Status != domain.ItemStatusPublished {
63				return &domain.ErrValidation{Field: "item_id", Message: "campaign requires a published item"}
64			}
65			campaign.ID = uuid.New()
66			campaign.Status = domain.CampaignStatusActive
67			campaign.CreatedAt = now
68			campaign.CurrentCommittedQty = 0
69			if err := s.campaigns.Create(txCtx, campaign); err != nil {
70				return err
71			}
72			return s.audit.Log(txCtx, "campaign.created", "campaign", campaign.ID, campaign.CreatedBy, map[string]interface{}{
73				"item_id":      campaign.ItemID.String(),
74				"min_quantity": campaign.MinQuantity,
75				"cutoff_time":  campaign.CutoffTime,
76			})
77		}); err != nil {
78			return nil, err
79		}
80		return campaign, nil
81	}
