91	func (s *CampaignServiceImpl) Join(ctx context.Context, campaignID, userID uuid.UUID, quantity int) (*domain.GroupBuyParticipant, error) {
92		now := time.Now().UTC()
93		var participant *domain.GroupBuyParticipant
94		if err := withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
95			campaign, err := s.campaigns.GetByID(txCtx, campaignID)
96			if err != nil {
97				return err
98			}
99			if campaign.Status != domain.CampaignStatusActive {
100				return &domain.ErrInvalidTransition{
101					Entity: "campaign",
102					From:   string(campaign.Status),
103					To:     "joined",
104				}
105			}
106			if campaign.IsAtCutoff(now) {
107				return &domain.ErrValidation{Field: "campaign_id", Message: "campaign has passed its cutoff time"}
108			}
109	
110			item, err := s.inventoryCoordinator().ensureReservable(txCtx, campaign.ItemID, quantity, now)
111			if err != nil {
112				return err
113			}
114			order := &domain.Order{
115				ID:          uuid.New(),
116				UserID:      userID,
117				ItemID:      campaign.ItemID,
118				CampaignID:  &campaignID,
119				Quantity:    quantity,
120				UnitPrice:   item.UnitPrice,
121				TotalAmount: float64(quantity) * item.UnitPrice,
122				Status:      domain.OrderStatusCreated,
123				AutoCloseAt: now.Add(domain.AutoCloseTimeout),
124				CreatedAt:   now,
125				UpdatedAt:   now,
126			}
127			if err := s.orders.Create(txCtx, order); err != nil {
128				return err
129			}
130			if err := s.timelines.Create(txCtx, &domain.OrderTimelineEntry{
131				ID:          uuid.New(),
132				OrderID:     order.ID,
133				Action:      "created",
134				Description: "order placed via campaign join",
135				PerformedBy: userID,
136				CreatedAt:   now,
137			}); err != nil {
138				return err
139			}
140	
141			participant = &domain.GroupBuyParticipant{
142				ID:         uuid.New(),
143				CampaignID: campaignID,
144				UserID:     userID,
145				Quantity:   quantity,
146				OrderID:    order.ID,
147				JoinedAt:   now,
148			}
149			if err := s.participants.Create(txCtx, participant); err != nil {
150				return err
151			}
152			committed, err := s.participants.CountCommittedQuantity(txCtx, campaignID)
153			if err != nil {
154				return err
155			}
156			campaign.CurrentCommittedQty = committed
157			if err := s.campaigns.Update(txCtx, campaign); err != nil {
158				return err
159			}
160			if err := s.inventoryCoordinator().applyChange(txCtx, campaign.ItemID, -quantity, "group-buy reservation", userID, now); err != nil {
161				return err
162			}
163			return s.audit.Log(txCtx, "campaign.joined", "campaign", campaignID, userID, map[string]interface{}{
164				"quantity": quantity,
165				"order_id": order.ID.String(),
166			})
167		}); err != nil {
168			return nil, err
169		}
170		return participant, nil
171	}
172	
173	func (s *CampaignServiceImpl) EvaluateAtCutoff(ctx context.Context, id uuid.UUID, now time.Time, performedBy uuid.UUID) error {
174		return withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
175			campaign, err := s.campaigns.GetByID(txCtx, id)
176			if err != nil {
177				return err
178			}
179	
180			committed, err := s.participants.CountCommittedQuantity(txCtx, id)
181			if err != nil {
182				return err
183			}
184			campaign.CurrentCommittedQty = committed
185	
186			if err := campaign.Evaluate(now); err != nil {
187				return err
188			}
189			if err := s.campaigns.Update(txCtx, campaign); err != nil {
190				return err
191			}
192			if campaign.Status == domain.CampaignStatusFailed {
193				participants, err := s.participants.ListByCampaign(txCtx, id)
194				if err != nil {
195					return err
196				}
197				for _, p := range participants {
198					order, err := s.orders.GetByID(txCtx, p.OrderID)
199					if err != nil {
200						return err
201					}
202					if order.Status == domain.OrderStatusCreated {
203						if err := domain.TransitionOrder(order, domain.OrderStatusAutoClosed); err != nil {
204							return err
205						}
206						order.CancelledAt = &now
207						order.UpdatedAt = now
208						if err := s.orders.Update(txCtx, order); err != nil {
209							return err
210						}
211						if err := s.inventoryCoordinator().applyChange(txCtx, order.ItemID, p.Quantity, "campaign failed - reservation released", p.UserID, now); err != nil {
212							return err
213						}
214					}
215				}
216			}
217			return s.audit.Log(txCtx, "campaign.evaluated", "campaign", campaign.ID, performedBy, map[string]interface{}{
218				"status":    string(campaign.Status),
219				"committed": campaign.CurrentCommittedQty,
220				"min":       campaign.MinQuantity,
221			})
222		})
223	}
224	
225	func (s *CampaignServiceImpl) Cancel(ctx context.Context, id uuid.UUID, performedBy uuid.UUID) error {
226		return withOptionalTransaction(ctx, s.txPool, func(txCtx context.Context) error {
227			campaign, err := s.campaigns.GetByID(txCtx, id)
228			if err != nil {
229				return err
230			}
231			if err := domain.TransitionCampaign(campaign, domain.CampaignStatusCancelled); err != nil {
232				return err
233			}
234			if err := s.campaigns.Update(txCtx, campaign); err != nil {
235				return err
236			}
237	
238			participants, err := s.participants.ListByCampaign(txCtx, id)
239			if err != nil {
240				return err
241			}
242			now := time.Now().UTC()
243			for _, p := range participants {
244				order, err := s.orders.GetByID(txCtx, p.OrderID)
245				if err != nil {
246					return err
247				}
248				if order.Status == domain.OrderStatusCreated {
249					if err := domain.TransitionOrder(order, domain.OrderStatusCancelled); err != nil {
250						return err
251					}
252					order.CancelledAt = &now
253					order.UpdatedAt = now
254					if err := s.orders.Update(txCtx, order); err != nil {
255						return err
256					}
257					if err := s.inventoryCoordinator().applyChange(txCtx, order.ItemID, p.Quantity, "campaign cancelled - reservation released", p.UserID, now); err != nil {
258						return err
259					}
260				}
261			}
262			return s.audit.Log(txCtx, "campaign.cancelled", "campaign", campaign.ID, performedBy, nil)
263		})
264	}
