425			n++
426		}
427		if start != nil {
428			q += fmt.Sprintf(" AND gbc.created_at >= $%d", n)
429			args = append(args, *start)
430			n++
431		}
432		if end != nil {
433			q += fmt.Sprintf(" AND gbc.created_at < $%d", n)
434			args = append(args, *end)
435		}
436		var rate float64
437		if err := s.pool.QueryRow(ctx, q, args...).Scan(&rate); err != nil {
438			return 0, err
439		}
440		return rate, nil
441	}
