185	// buildFilteredQuery appends parameterized WHERE clauses to a base query using
186	// the provided filter map and column mapping. The "_date" key in colMap defines
187	// which column is used for "from" and "to" range filters. Returns the final
188	// query string and the argument slice.
189	func buildFilteredQuery(baseQuery string, filters map[string]string, colMap map[string]string, suffix string) (string, []interface{}) {
190		q := baseQuery
191		args := []interface{}{}
192		n := 1
193		hasWhere := strings.Contains(strings.ToUpper(baseQuery), "WHERE")
194		conj := func() string {
195			if hasWhere {
196				return " AND "
197			}
198			hasWhere = true
199			return " WHERE "
200		}
201	
202		for filterKey, colName := range colMap {
203			if filterKey == "_date" {
204				continue
205			}
206			if v, ok := filters[filterKey]; ok && v != "" {
207				q += conj() + fmt.Sprintf("%s = $%d", colName, n)
208				args = append(args, v)
209				n++
210			}
211		}
212	
213		dateCol := colMap["_date"]
214		if dateCol != "" {
215			if v, ok := filters["from"]; ok && v != "" {
216				q += conj() + fmt.Sprintf("%s >= $%d", dateCol, n)
217				args = append(args, v)
218				n++
219			}
220			if v, ok := filters["to"]; ok && v != "" {
221				q += conj() + fmt.Sprintf("%s <= $%d", dateCol, n)
222				args = append(args, v)
223				n++
224			}
225		}
226	
227		q += suffix
228		return q, args
229	}
