231	// queryRows executes a query and returns each row as a map[string]interface{}.
232	func (s *ReportServiceImpl) queryRows(ctx context.Context, query string, args ...interface{}) ([]map[string]interface{}, error) {
233		rows, err := s.pool.Query(ctx, query, args...)
234		if err != nil {
235			return nil, err
236		}
237		defer rows.Close()
238	
239		fields := rows.FieldDescriptions()
240		var result []map[string]interface{}
241		for rows.Next() {
242			values, err := rows.Values()
243			if err != nil {
244				return nil, err
245			}
246			row := make(map[string]interface{}, len(fields))
247			for i, field := range fields {
248				row[string(field.Name)] = values[i]
249			}
250			result = append(result, row)
251		}
252		if err := rows.Err(); err != nil {
253			return nil, err
254		}
255		if result == nil {
256			result = []map[string]interface{}{}
257		}
258		return result, nil
259	}
