261	// GenerateExport creates an export file for the given report in the requested
262	// format and records the job in the database.
263	// callerRole is checked against the report's AllowedRoles as a second authorization layer.
264	func (s *ReportServiceImpl) GenerateExport(ctx context.Context, reportID uuid.UUID, format domain.ExportFormat, parameters map[string]string, createdBy uuid.UUID, callerRole domain.UserRole) (*domain.ExportJob, error) {
265		if !format.IsValid() {
266			return nil, &domain.ErrValidation{Field: "format", Message: "unsupported export format"}
267		}
268	
269		report, err := s.reportRepo.GetByID(ctx, reportID)
270		if err != nil {
271			return nil, err
272		}
273	
274		allowed := false
275		for _, r := range report.AllowedRoles {
276			if r == callerRole {
277				allowed = true
278				break
279			}
280		}
281		if !allowed {
282			return nil, domain.ErrForbidden
283		}
284	
285		filename := domain.GenerateExportFilename(report.ReportType, format, time.Now().UTC())
286	
287		job := &domain.ExportJob{
288			ID:        uuid.New(),
289			ReportID:  reportID,
290			Format:    format,
291			Filename:  filename,
292			Status:    domain.ExportStatusPending,
293			CreatedBy: createdBy,
294			CreatedAt: time.Now().UTC(),
295		}
296	
297		if err := s.exportRepo.Create(ctx, job); err != nil {
298			return nil, err
299		}
300	
301		filePath := filepath.Join(s.cfg.ExportPath, filename)
302	
303		if err := os.MkdirAll(s.cfg.ExportPath, 0755); err != nil {
304			job.Status = domain.ExportStatusFailed
305			_ = s.exportRepo.Update(ctx, job)
306			return job, err
307		}
308	
309		records, dataErr := s.queryReportData(ctx, report.ReportType, sanitizeReportFilters(report.ReportType, parameters))
310		if dataErr != nil {
311			job.Status = domain.ExportStatusFailed
312			_ = s.exportRepo.Update(ctx, job)
313			return job, dataErr
314		}
315		// Apply role-based masking: only admins and operations managers see raw PII.
316		records = maskExportRecords(records, callerRole)
317		data := recordsToRows(report.ReportType, records)
318	
319		var writeErr error
320		switch format {
321		case domain.ExportFormatCSV:
322			writeErr = writeCSV(filePath, data)
323		case domain.ExportFormatPDF:
324			writeErr = writePDF(filePath, report.ReportType, data)
325		}
326	
327		if writeErr != nil {
328			job.Status = domain.ExportStatusFailed
329			_ = s.exportRepo.Update(ctx, job)
330			return job, writeErr
331		}
332	
333		now := time.Now().UTC()
334		job.Status = domain.ExportStatusCompleted
335		job.FilePath = filePath
336		job.CompletedAt = &now
337	
338		if err := s.exportRepo.Update(ctx, job); err != nil {
339			return job, err
340		}
341	
342		_ = s.auditSvc.Log(ctx, "export.generated", "export_job", job.ID, createdBy, map[string]interface{}{
343			"report_type": report.ReportType,
344			"format":      string(format),
345			"filename":    filename,
346		})
347	
348		return job, nil
349	}
