351	func sanitizeReportFilters(reportType string, filters map[string]string) map[string]string {
352		if len(filters) == 0 {
353			return nil
354		}
355		allowedByReportType := map[string]map[string]bool{
356			"member_growth":      {"location_id": true, "status": true, "from": true, "to": true},
357			"churn":              {"location_id": true, "from": true, "to": true},
358			"renewal_rate":       {"location_id": true},
359			"engagement":         {"status": true, "from": true, "to": true},
360			"class_fill_rate":    {"status": true, "from": true, "to": true},
361			"coach_productivity": {"location_id": true, "coach_id": true},
362			"inventory_summary":  {"category": true, "status": true},
363			"procurement_summary": {"status": true, "from": true, "to": true},
364			"landed_cost_report": {"item_id": true, "purchase_order_id": true, "period": true, "from": true, "to": true},
365		}
366	
367		allowed := allowedByReportType[reportType]
368		if len(allowed) == 0 {
369			return nil
370		}
371	
372		sanitized := make(map[string]string)
373		for key, value := range filters {
374			if allowed[key] && value != "" {
375				sanitized[key] = value
376			}
377		}
378		return sanitized
379	}
