491	// writeCSV writes the given records as a CSV file at path.
492	func writeCSV(path string, records [][]string) error {
493		f, err := os.Create(path)
494		if err != nil {
495			return err
496		}
497		defer f.Close()
498	
499		w := csv.NewWriter(f)
500		if err := w.WriteAll(records); err != nil {
501			return err
502		}
503		w.Flush()
504		return w.Error()
505	}
