8	func TestAuth_LoginSessionLogoutFlow(t *testing.T) {
9		app := newIntegrationApp(t)
10		admin := app.seedUser(t, "administrator", nil)
11	
12		loginRec := app.post(t, "/api/v1/auth/login", map[string]string{
13			"email":    admin.Email,
14			"password": admin.Password,
15		}, nil)
16		requireStatus(t, loginRec, http.StatusOK)
17	
18		cookies := responseCookies(loginRec)
19		if len(cookies) == 0 {
20			t.Fatal("expected login to set at least one cookie")
21		}
22	
23		loginBody := decodeSuccess[map[string]any](t, loginRec)
24		if loginBody["user"] == nil {
25			t.Fatal("expected login response to include user payload")
26		}
27		if loginBody["session"] == nil {
28			t.Fatal("expected login response to include session payload")
29		}
30		sessionBody, ok := loginBody["session"].(map[string]any)
31		if !ok {
32			t.Fatalf("expected session payload object, got %#v", loginBody["session"])
33		}
34		if _, hasToken := sessionBody["token"]; hasToken {
35			t.Fatal("did not expect login response to include session token in body")
36		}
37	
38		sessionRec := app.get(t, "/api/v1/auth/session", cookies)
39		requireStatus(t, sessionRec, http.StatusOK)
40	
41		logoutRec := app.post(t, "/api/v1/auth/logout", map[string]string{}, cookies)
42		requireStatus(t, logoutRec, http.StatusOK)
43		logoutBody := decodeSuccess[map[string]any](t, logoutRec)
44		if logoutBody["message"] != "logged out" {
45			t.Fatalf("expected logout message, got %#v", logoutBody["message"])
46		}
47	
48		postLogoutSession := app.get(t, "/api/v1/auth/session", cookies)
49		requireStatus(t, postLogoutSession, http.StatusUnauthorized)
50	}
