101	func newIntegrationAppWithConfig(t *testing.T, cfg platform.Config) *integrationApp {
102		t.Helper()
103	
104		apiDBMu.Lock()
105		t.Cleanup(func() {
106			apiDBMu.Unlock()
107		})
108	
109		resetDatabase(t, cfg)
110	
111		testDump := func(ctx context.Context, connStr, destPath string) error {
112			_ = ctx
113			_ = connStr
114			if err := os.MkdirAll(filepath.Dir(destPath), 0755); err != nil {
115				return err
116			}
117			return os.WriteFile(destPath, []byte("integration-test-backup"), 0600)
118		}
119	
120		app, err := bootstrap.NewApp(context.Background(), cfg, platform.NewLogger("error"), testDump)
121		if err != nil {
122			t.Fatalf("bootstrap app: %v", err)
123		}
124	
125		// Start a real HTTP test server so all API calls go through the full HTTP
126		// stack (middleware, routing, serialisation) over an actual TCP connection.
127		ts := httptest.NewServer(app.Echo)
128		t.Cleanup(ts.Close)
129		t.Cleanup(func() {
130			app.Close()
131		})
132	
133		// Disable automatic redirect following so tests receive the raw response
134		// status exactly as the server sends it.
135		client := &http.Client{
136			CheckRedirect: func(_ *http.Request, _ []*http.Request) error {
137				return http.ErrUseLastResponse
138			},
139		}
140	
141		return &integrationApp{
142			app:    app,
143			cfg:    cfg,
144			server: ts,
145			client: client,
146		}
147	}
