175	func resetDatabase(t *testing.T, cfg platform.Config) {
176		t.Helper()
177	
178		db, err := sql.Open("pgx", cfg.DatabaseURL)
179		if err != nil {
180			t.Fatalf("open database: %v", err)
181		}
182		defer db.Close()
183		db.SetMaxOpenConns(1)
184		db.SetMaxIdleConns(1)
185	
186		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
187		defer cancel()
188	
189		if err := db.PingContext(ctx); err != nil {
190			t.Fatalf("ping database: %v", err)
191		}
192	
193		statements := []string{
194			`DROP SCHEMA IF EXISTS public CASCADE`,
195			`CREATE SCHEMA public`,
196			`CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA public`,
197		}
198		for _, stmt := range statements {
199			if _, err := db.ExecContext(ctx, stmt); err != nil {
200				t.Fatalf("exec %q: %v", stmt, err)
201			}
202		}
203	
204		if _, err := db.ExecContext(ctx, `SET search_path TO public`); err != nil {
205			t.Fatalf("set search_path: %v", err)
206		}
207	
208		gooseOnce.Do(func() {
209			if err := goose.SetDialect("postgres"); err != nil {
210				panic(err)
211			}
212		})
213	
214		if err := goose.UpContext(ctx, db, filepath.Join(backendRoot(t), "database", "migrations")); err != nil {
215			t.Fatalf("run migrations: %v", err)
216		}
217	
218		seedSQL, err := os.ReadFile(filepath.Join(backendRoot(t), "database", "seeds", "seed.sql"))
219		if err != nil {
220			t.Fatalf("read seed.sql: %v", err)
221		}
222		if _, err := db.ExecContext(ctx, string(seedSQL)); err != nil {
223			t.Fatalf("run seed.sql: %v", err)
224		}
225	}
