244	func (a *integrationApp) request(t *testing.T, method, path string, body any, cookies []*http.Cookie) *httptest.ResponseRecorder {
245		t.Helper()
246	
247		var bodyReader io.Reader
248		if body != nil {
249			payload, err := json.Marshal(body)
250			if err != nil {
251				t.Fatalf("marshal request body: %v", err)
252			}
253			bodyReader = bytes.NewReader(payload)
254		}
255	
256		req, err := http.NewRequest(method, a.server.URL+path, bodyReader)
257		if err != nil {
258			t.Fatalf("create request: %v", err)
259		}
260		if body != nil {
261			req.Header.Set("Content-Type", "application/json")
262		}
263		for _, cookie := range cookies {
264			req.AddCookie(cookie)
265		}
266	
267		resp, err := a.client.Do(req)
268		if err != nil {
269			t.Fatalf("do request %s %s: %v", method, path, err)
270		}
271		defer resp.Body.Close()
272	
273		respBody, err := io.ReadAll(resp.Body)
274		if err != nil {
275			t.Fatalf("read response body: %v", err)
276		}
277	
278		// Wrap the real HTTP response in a ResponseRecorder so all existing
279		// assertions (rec.Code, rec.Body.Bytes(), rec.Header()) stay unchanged.
280		return &httptest.ResponseRecorder{
281			Code:      resp.StatusCode,
282			HeaderMap: resp.Header,
283			Body:      bytes.NewBuffer(respBody),
284		}
285	}
