307	func decodeSuccess[T any](t *testing.T, rec *httptest.ResponseRecorder) T {
308		t.Helper()
309	
310		var envelope struct {
311			Data T `json:"data"`
312		}
313		if err := json.Unmarshal(rec.Body.Bytes(), &envelope); err != nil {
314			t.Fatalf("decode success body: %v\nbody=%s", err, rec.Body.String())
315		}
316		return envelope.Data
317	}
318	
319	func decodePaginated[T any](t *testing.T, rec *httptest.ResponseRecorder) ([]T, dto.PaginationMeta) {
320		t.Helper()
321	
322		var envelope struct {
323			Data       []T                `json:"data"`
324			Pagination dto.PaginationMeta `json:"pagination"`
325		}
326		if err := json.Unmarshal(rec.Body.Bytes(), &envelope); err != nil {
327			t.Fatalf("decode paginated body: %v\nbody=%s", err, rec.Body.String())
328		}
329		return envelope.Data, envelope.Pagination
330	}
331	
332	func decodeError(t *testing.T, rec *httptest.ResponseRecorder) errorEnvelope {
333		t.Helper()
334	
335		var envelope errorEnvelope
336		if err := json.Unmarshal(rec.Body.Bytes(), &envelope); err != nil {
337			t.Fatalf("decode error body: %v\nbody=%s", err, rec.Body.String())
338		}
339		return envelope
340	}
