342	func requireStatus(t *testing.T, rec *httptest.ResponseRecorder, want int) {
343		t.Helper()
344		if rec.Code != want {
345			t.Fatalf("expected status %d, got %d: %s", want, rec.Code, rec.Body.String())
346		}
347	}
